INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Abro Scratch y veo el escenario vacío con el gato naranja","Arrastro un bloque de movimiento para que el gato avance diez pasos","Añado un bloque de sonido para que maúlle al llegar al borde","Conecto un bloque de control para que repita la acción cinco veces","Pulso la bandera verde y el gato se mueve maullando por la pantalla"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Quiero crear un juego sencillo donde el gato persiga al ratón","Dibujo un nuevo personaje con forma de ratón gris pequeño","Programo el ratón para que aparezca en posiciones aleatorias del escenario","Añado puntos cada vez que el gato toca al ratón con el puntero","Muestro la puntuación final cuando se acaba el tiempo del juego"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Un algoritmo es una lista ordenada de pasos para resolver un problema","Primero debo entender bien qué problema quiero resolver exactamente","Después pienso en los pasos necesarios y los ordeno de forma lógica","Compruebo que cada paso sea claro y no tenga ambigüedades posibles","Finalmente verifico que el algoritmo produce el resultado correcto esperado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Quiero programar una animación con un personaje que camina por la calle","Selecciono un fondo de ciudad desde la biblioteca de escenarios de Scratch","Elijo un personaje con varios disfraces que simulan el movimiento al caminar","Uso un bucle para alternar los disfraces mientras el personaje se desplaza","La animación muestra al personaje caminando de izquierda a derecha sin parar"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Necesito que mi programa tome una decisión según lo que escriba el usuario","Uso el bloque preguntar para que Scratch pida el nombre al jugador","Guardo la respuesta en una variable llamada nombre del jugador","Uso un bloque condicional si-entonces para comprobar si el nombre es correcto","El programa saluda al jugador por su nombre si la respuesta es válida"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Dibujo un laberinto sencillo en el editor de fondos de Scratch","Coloco al personaje en la entrada del laberinto usando coordenadas exactas","Programo las teclas de flecha para mover al personaje en cuatro direcciones","Añado una condición que detecta si el personaje toca las paredes negras","Si toca la pared el personaje vuelve al inicio del laberinto automáticamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Quiero hacer un programa que calcule la tabla de multiplicar de un número","Pido al usuario que introduzca un número del uno al diez","Creo una variable contador que empieza en uno y llega hasta diez","Dentro del bucle multiplico el número del usuario por el contador actual","Muestro cada resultado en pantalla formando la tabla de multiplicar completa"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Descubro que mi programa de Scratch tiene un error porque no funciona bien","Reviso los bloques uno por uno buscando dónde está el fallo exacto","Encuentro que un bloque de repetición tiene un número equivocado de veces","Cambio el valor incorrecto por el número adecuado en el bloque de control","Ejecuto el programa otra vez y compruebo que ahora funciona perfectamente bien"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Voy a crear un cuestionario interactivo de preguntas y respuestas en Scratch","Programo la primera pregunta usando el bloque preguntar y esperar la respuesta","Uso un condicional para comprobar si la respuesta del usuario es correcta","Si acierta sumo un punto y si falla muestro la respuesta correcta","Al final muestro la puntuación total de aciertos sobre el total de preguntas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Aprendo que un bucle sirve para repetir instrucciones varias veces seguidas","En Scratch hay un bloque que dice repetir un número concreto de veces","También existe el bloque repetir por siempre que nunca se detiene solo","Dentro del bucle coloco las acciones que quiero que se repitan cada vez","Gracias a los bucles evito escribir el mismo código muchas veces seguidas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Quiero que mi personaje cambie de color cuando pulse la tecla espacio","Añado un evento que detecta cuándo se presiona la tecla espacio del teclado","Dentro del evento coloco un bloque que cambia el efecto de color","El personaje va cambiando de tonalidad cada vez que pulso la tecla espacio","Si pulso muchas veces seguidas el personaje pasa por todos los colores posibles"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Creo un diagrama de flujo para representar un algoritmo de forma visual","Dibujo un óvalo de inicio que marca dónde comienza el proceso del algoritmo","Uso rectángulos para representar cada acción o paso del proceso completo","Los rombos representan decisiones donde el camino se divide en dos opciones","Termino con un óvalo de fin que indica dónde acaba el algoritmo diseñado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Programo un cronómetro sencillo que cuenta los segundos desde cero hacia arriba","Creo una variable llamada tiempo y le asigno el valor inicial de cero","Dentro de un bucle infinito espero un segundo y sumo uno a la variable","El cronómetro muestra en pantalla los segundos que van pasando continuamente","Añado un botón para detener el cronómetro cuando pulse la tecla de parar"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Quiero crear un programa que dibuje figuras geométricas usando el lápiz de Scratch","Bajo el lápiz para que el personaje deje un rastro visible al moverse","Programo que avance cien pasos y gire noventa grados a la derecha exactamente","Repito esos dos bloques cuatro veces dentro de un bucle de repetición","El resultado es un cuadrado perfecto dibujado en el centro del escenario"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Aprendo qué es una variable observando cómo funciona una caja con etiqueta","Una variable es como una caja donde guardo un dato con un nombre","Puedo guardar números como la edad o textos como el nombre del jugador","Durante el programa puedo cambiar el valor guardado dentro de esa variable","Al final del programa leo la variable para mostrar su valor en pantalla"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Diseño un juego de atrapar manzanas que caen desde la parte superior","Creo un personaje cesta que se mueve a izquierda y derecha con el ratón","Las manzanas aparecen arriba en posiciones aleatorias y caen hacia abajo lentamente","Si la cesta toca una manzana se suma un punto al marcador del jugador","El juego termina cuando tres manzanas llegan al suelo sin ser atrapadas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Necesito entender la diferencia entre entrada salida y proceso en un algoritmo","La entrada son los datos que el usuario proporciona al programa inicialmente","El proceso son las operaciones que el programa realiza con esos datos recibidos","La salida es el resultado final que el programa muestra al usuario","Todo algoritmo sigue este esquema básico de entrada proceso y salida obligatoriamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Creo mi primer proyecto colaborativo en Scratch con un compañero de clase","Diseño los personajes mientras mi compañero programa los movimientos y las interacciones","Compartimos el proyecto en la comunidad de Scratch para que otros lo vean","Otros usuarios prueban nuestro juego y nos dejan comentarios con sugerencias útiles","Mejoramos el proyecto añadiendo las ideas que más nos gustaron de los comentarios"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Quiero que mi programa genere un número aleatorio para un juego de adivinanzas","Uso el bloque de número al azar entre uno y cien de Scratch","El programa pide al jugador que intente adivinar el número secreto generado","Si el intento es menor le dice que el número secreto es más grande","Cuando acierta el programa muestra un mensaje de felicitación con el número de intentos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Un evento en Scratch es algo que ocurre y hace que el programa reaccione","El evento más común es pulsar la bandera verde para iniciar el programa","También puedo usar eventos de teclado como presionar una tecla específica cualquiera","Los mensajes son eventos que un personaje envía y otro personaje puede recibir","Gracias a los eventos diferentes partes del programa se comunican entre sí perfectamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Diseño una historia interactiva donde el usuario elige qué camino seguir","El personaje principal llega a una bifurcación con dos opciones posibles diferentes","Pregunto al usuario si quiere ir por el bosque o por la montaña","Según la elección el personaje vive una aventura completamente diferente y emocionante","Al final de cada camino muestro un mensaje distinto según las decisiones tomadas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Aprendo a usar coordenadas para colocar personajes en posiciones exactas del escenario","El escenario de Scratch tiene un eje horizontal X y un eje vertical Y","El centro del escenario tiene las coordenadas X igual a cero Y igual a cero","Puedo mover un personaje a cualquier punto indicando sus coordenadas X e Y","Esto me permite colocar los elementos del juego exactamente donde los necesito"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Creo un programa que simula un semáforo cambiando de color automáticamente cada vez","Dibujo tres disfraces del personaje en rojo amarillo y verde respectivamente","El programa empieza mostrando el disfraz rojo durante cinco segundos de espera","Después cambia al amarillo durante dos segundos y luego pasa al color verde","El bucle se repite infinitamente simulando el funcionamiento real de un semáforo urbano"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Quiero hacer un programa que convierta grados Celsius a Fahrenheit automáticamente","Pido al usuario que introduzca la temperatura en grados Celsius por teclado","Aplico la fórmula multiplicando por nueve quintos y sumando treinta y dos al resultado","Guardo el resultado en una variable llamada temperatura en Fahrenheit para mostrarlo","Muestro el resultado final con un mensaje claro indicando ambas temperaturas al usuario"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Descubro que los operadores en Scratch sirven para hacer cálculos y comparaciones","Los operadores matemáticos permiten sumar restar multiplicar y dividir números fácilmente","Los operadores de comparación comprueban si un valor es mayor menor o igual","Los operadores lógicos como Y y O combinan varias condiciones en una sola","Uso estos operadores dentro de condicionales y bucles para tomar decisiones en programas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Programo un piano virtual en Scratch donde cada tecla produce una nota musical","Creo varios personajes que representan las teclas blancas y negras del piano","Asigno una nota musical diferente a cada personaje usando los bloques de sonido","Cuando el usuario hace clic en una tecla suena la nota correspondiente al instante","Puedo tocar melodías sencillas haciendo clic en las teclas en el orden correcto"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{1}', '["Aprendo a descomponer un problema grande en partes más pequeñas y manejables","Quiero crear un juego complejo pero no sé por dónde empezar a programarlo","Divido el proyecto en tareas pequeñas como diseñar personajes y programar movimientos","Resuelvo cada tarea por separado probando que funcione correctamente antes de seguir","Al unir todas las partes pequeñas consigo que el juego completo funcione sin errores"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Declaro tres variables de tipo entero para almacenar las notas de tres exámenes","Pido al usuario que introduzca cada nota una por una desde el teclado","Sumo las tres notas y guardo el resultado en una variable llamada total","Divido el total entre tres para obtener la media aritmética de las calificaciones","Muestro en pantalla la nota media con un mensaje indicando si ha aprobado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Creo un bucle while que se ejecuta mientras el usuario no escriba la palabra salir","Dentro del bucle el programa pide al usuario que introduzca un dato nuevo","El dato se añade a una lista que almacena todos los valores introducidos hasta ahora","El bucle comprueba la condición de salida al principio de cada nueva iteración","Cuando el usuario escribe salir el bucle termina y muestra todos los datos guardados"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Necesito crear una función que calcule el área de un rectángulo dado","Defino la función con dos parámetros que representan la base y la altura","Dentro de la función multiplico la base por la altura y devuelvo el resultado","Llamo a la función desde el programa principal pasándole los valores concretos necesarios","El programa muestra el área calculada sin tener que repetir el código cada vez"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Diseño un programa que ordena una lista de números de menor a mayor valor","Creo una lista con diez números desordenados introducidos por el usuario del programa","Implemento el algoritmo de ordenación burbuja comparando elementos consecutivos de la lista","En cada pasada los números mayores van subiendo hacia el final de la lista","Tras varias pasadas la lista queda completamente ordenada de menor a mayor correctamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Aprendo la diferencia entre un bucle for y un bucle while en programación","El bucle for se usa cuando sabemos exactamente cuántas veces queremos repetir algo","El bucle while se usa cuando la repetición depende de una condición que puede cambiar","Ambos bucles pueden hacer lo mismo pero cada uno es mejor en situaciones diferentes","Elegir el bucle adecuado hace que el código sea más claro y fácil de entender"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Creo una página web sencilla usando HTML con una estructura básica bien organizada","Escribo la etiqueta html que contiene las secciones head y body del documento","En el head incluyo el título de la página y los metadatos de codificación","En el body añado encabezados párrafos e imágenes que forman el contenido visible","Abro el archivo en el navegador y compruebo que la página se muestra correctamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Programo un conversor de monedas que transforma euros a dólares y libras fácilmente","Defino las tasas de cambio actuales como constantes al inicio del programa ejecutable","El usuario selecciona la moneda de destino entre las opciones disponibles del menú","El programa multiplica la cantidad en euros por la tasa de cambio correspondiente","Muestra el resultado con dos decimales y el símbolo de la moneda elegida finalmente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Necesito recorrer una lista de alumnos para encontrar al que tiene la nota máxima","Creo una variable llamada mejor nota y la inicializo con el valor cero","Uso un bucle for para recorrer cada elemento de la lista de calificaciones","Si la nota actual es mayor que mejor nota actualizo la variable con este valor","Al terminar el bucle la variable contiene la nota más alta de toda la clase"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Descubro qué es un string o cadena de texto y cómo manipularlo en código","Un string es una secuencia de caracteres encerrada entre comillas dobles o simples","Puedo concatenar dos strings uniéndolos con el operador más para formar uno nuevo","La función longitud me dice cuántos caracteres tiene una cadena de texto determinada","Puedo extraer partes de un string usando índices que señalan posiciones dentro de él"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Creo un programa de piedra papel o tijera contra el ordenador usando condicionales","El usuario elige su jugada escribiendo piedra papel o tijera en el teclado","El ordenador genera una jugada aleatoria entre las tres opciones posibles del juego","Comparo ambas jugadas usando estructuras condicionales anidadas para determinar el ganador","Muestro el resultado indicando si ha ganado perdido o ha habido un empate justo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Aprendo a usar los comentarios en el código para explicar qué hace cada parte","Los comentarios son líneas de texto que el ordenador ignora al ejecutar el programa","Sirven para que otros programadores entiendan la lógica de mi código más fácilmente","Un buen comentario explica el porqué de una decisión no solo lo que hace","Comentar el código es una buena práctica que facilita el mantenimiento del programa"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Diseño un programa que genera contraseñas aleatorias seguras de ocho caracteres mínimo","Creo listas separadas con letras mayúsculas minúsculas números y símbolos especiales disponibles","El programa selecciona caracteres aleatorios de cada lista para garantizar la variedad necesaria","Une todos los caracteres seleccionados en una sola cadena formando la contraseña final","Muestra la contraseña generada y recomienda al usuario guardarla en un lugar seguro"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Aprendo a usar una estructura de datos tipo diccionario para almacenar pares clave-valor","Un diccionario asocia cada clave única con un valor específico como nombre y teléfono","Creo un diccionario con los nombres de cinco compañeros y sus números de teléfono","Puedo buscar el teléfono de cualquier compañero usando su nombre como clave de búsqueda","También puedo añadir nuevos contactos o modificar los existentes de forma muy sencilla"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Programo un juego de ahorcado donde el usuario adivina una palabra letra a letra","Elijo una palabra secreta de una lista y creo guiones bajos para cada letra","El jugador propone una letra y el programa comprueba si está en la palabra","Si la letra existe se revela en su posición correcta sustituyendo el guión bajo","Si falla se dibuja una parte del muñeco y al completarlo el juego termina"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Necesito validar los datos de entrada para que el usuario no introduzca valores incorrectos","Pido al usuario que escriba su edad y guardo el dato en una variable temporal","Compruebo que el dato sea un número entero positivo y no una letra o símbolo","Si el dato no es válido muestro un mensaje de error y vuelvo a pedirlo","El bucle de validación se repite hasta que el usuario introduce un dato correcto"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Creo un menú interactivo con varias opciones numeradas que el usuario puede elegir","Muestro las opciones disponibles como calcular área ver historial o salir del programa","El usuario escribe el número de la opción que desea ejecutar en ese momento","Uso una estructura switch o múltiples condicionales para ejecutar la opción seleccionada correctamente","Después de ejecutar la opción el menú vuelve a aparecer hasta que elija salir"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Aprendo a leer y escribir datos en un fichero de texto desde mi programa","Abro un archivo en modo escritura y guardo los resultados del programa dentro","Cierro el archivo para asegurar que los datos se guardan correctamente en disco","Después abro el mismo archivo en modo lectura para recuperar los datos guardados","Leo el contenido línea por línea y lo muestro por pantalla al usuario final"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Programo un calculador de índice de masa corporal que evalúa el peso del usuario","Pido al usuario que introduzca su peso en kilogramos y su altura en metros","Calculo el IMC dividiendo el peso entre la altura al cuadrado usando la fórmula","Uso condicionales para clasificar el resultado en bajo peso normal sobrepeso u obesidad","Muestro el valor del IMC junto con la categoría correspondiente y una recomendación breve"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Descubro cómo funcionan los operadores lógicos AND OR y NOT en las condiciones","El operador AND devuelve verdadero solo cuando ambas condiciones se cumplen a la vez","El operador OR devuelve verdadero cuando al menos una de las condiciones se cumple","El operador NOT invierte el valor de una condición convirtiendo verdadero en falso siempre","Combinar estos operadores permite crear condiciones complejas para tomar decisiones más precisas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Creo un programa que cuenta las vocales y consonantes de una frase introducida","El usuario escribe una frase cualquiera y el programa la recorre carácter por carácter","Para cada carácter compruebo si es una vocal comparándolo con la lista de vocales","Si es una letra pero no es vocal la cuento como consonante en otro contador","Al final muestro el total de vocales y consonantes encontradas en toda la frase"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Aprendo a depurar errores de ejecución que hacen que mi programa se detenga inesperadamente","Un error de ejecución ocurre cuando el programa intenta hacer algo imposible como dividir entre cero","Uso bloques try-catch para capturar el error y evitar que el programa se cierre","Dentro del catch muestro un mensaje explicativo al usuario indicando qué ha fallado exactamente","Así el programa sigue funcionando aunque ocurra un error durante la ejecución del código"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Diseño una hoja de estilos CSS para dar formato visual a mi página web","Selecciono los elementos HTML que quiero modificar usando selectores de tipo y clase","Cambio el color de fondo del cuerpo a un tono azul claro muy suave","Aplico un tipo de letra sans-serif y un tamaño de dieciséis píxeles al texto","Añado márgenes y bordes redondeados a los párrafos para mejorar la presentación visual"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Programo un temporizador de cuenta atrás que avisa cuando el tiempo se acaba completamente","El usuario introduce los minutos de cuenta atrás que desea configurar al iniciar","El programa convierte los minutos a segundos y comienza a restar uno cada segundo","Muestra el tiempo restante actualizado en formato de minutos y segundos en pantalla","Cuando llega a cero reproduce un sonido de alarma y muestra un mensaje de aviso"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Creo un programa que simula el lanzamiento de un dado virtual muchas veces","Uso un generador de números aleatorios que produce valores entre uno y seis siempre","Lanzo el dado mil veces y cuento cuántas veces sale cada número en total","Calculo el porcentaje de aparición de cada cara del dado dividiendo entre mil","Compruebo que todos los números salen aproximadamente el mismo número de veces observado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Aprendo a crear una lista enlazada y a recorrerla desde el primer elemento","Cada nodo de la lista contiene un dato y una referencia al siguiente nodo","Creo el primer nodo con el valor diez y lo asigno como cabeza de lista","Añado un segundo nodo con valor veinte y lo enlazo después del primer nodo","Recorro la lista desde la cabeza imprimiendo cada valor hasta llegar al final nulo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Programo un sistema de registro de usuarios con nombre correo y contraseña cifrada","El programa pide al nuevo usuario que introduzca su nombre completo y correo electrónico","Solicita una contraseña que debe tener al menos ocho caracteres y un número obligatorio","Cifro la contraseña antes de guardarla junto al resto de datos del usuario","Muestro un mensaje confirmando que el registro se ha completado correctamente y con éxito"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Diseño un formulario HTML con campos de texto botones y listas desplegables funcionales","Creo un formulario con la etiqueta form y defino el método de envío POST","Añado campos de entrada para el nombre el email y un mensaje de texto","Incluyo una lista desplegable con opciones de asunto como consulta queja o sugerencia","Coloco un botón de envío que procesa los datos cuando el usuario hace clic"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Creo un programa que cifra mensajes usando el cifrado César de desplazamiento tres posiciones","El usuario introduce un mensaje de texto que quiere cifrar de forma secreta","El programa recorre cada letra y la sustituye por la que está tres posiciones después","Los espacios y signos de puntuación se mantienen sin cambiar en el mensaje cifrado","Muestro el mensaje cifrado y ofrezco la opción de descifrar otro mensaje codificado previamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Aprendo que un array bidimensional es como una tabla con filas y columnas organizadas","Creo un array de tres filas y cuatro columnas para almacenar las notas trimestrales","Cada fila representa un trimestre y cada columna representa una asignatura del curso","Accedo a un elemento concreto indicando el número de fila y columna entre corchetes","Recorro toda la tabla con dos bucles anidados para calcular la media general del año"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{2}', '["Programo un juego de preguntas tipo trivial con categorías de ciencias historia y deportes","Almaceno las preguntas y respuestas en listas separadas organizadas por categoría temática","El jugador elige una categoría y el programa selecciona una pregunta aleatoria de esa categoría","Tiene quince segundos para responder antes de que se acabe el tiempo disponible","Se acumulan puntos por cada respuesta correcta y al final se muestra la puntuación total"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Instalo Python en mi ordenador descargando la última versión desde la web oficial","Abro la terminal de comandos y escribo python para verificar que la instalación funciona","Creo mi primer archivo con extensión punto py usando un editor de texto básico","Escribo la instrucción print con el mensaje hola mundo entre paréntesis y comillas","Ejecuto el archivo desde la terminal y el mensaje aparece impreso en la consola"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Aprendo a usar listas por comprensión en Python para crear listas de forma compacta","La sintaxis básica usa corchetes con una expresión seguida de un bucle for dentro","Creo una lista con los cuadrados de los números del uno al diez automáticamente","Añado una condición if para incluir solo los cuadrados de los números pares mayores","El resultado es una lista filtrada generada en una sola línea de código eficiente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Diseño un programa en Python que lee un archivo CSV con datos de ventas","Importo la biblioteca csv de Python para manejar archivos con valores separados por comas","Abro el archivo en modo lectura y creo un objeto lector que recorre cada fila","Extraigo las columnas de producto cantidad y precio de cada registro del archivo completo","Calculo el total de ventas multiplicando cantidad por precio y sumando todos los resultados"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Implemento una función recursiva en Python que calcula el factorial de un número entero","La función recibe un número n como parámetro y comprueba si es igual a cero","Si n es cero devuelve uno porque el factorial de cero es uno por definición","Si no la función se llama a sí misma con n menos uno y multiplica","Las llamadas se apilan hasta llegar al caso base y se resuelven hacia atrás"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Creo un servidor web sencillo en Python usando la biblioteca Flask para aplicaciones","Instalo Flask con el gestor de paquetes pip escribiendo pip install flask en terminal","Defino una ruta principal que devuelve un saludo cuando alguien visita la página inicial","Arranco el servidor en modo desarrollo y accedo a la dirección localhost en el navegador","La página web muestra el saludo confirmando que el servidor funciona correctamente desde Python"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Aprendo a manejar excepciones en Python para que los errores no detengan el programa","Envuelvo el código que puede fallar dentro de un bloque try para proteger la ejecución","Si ocurre un error el flujo salta al bloque except que gestiona la situación","Puedo especificar el tipo de excepción como ValueError o ZeroDivisionError para ser preciso","El bloque finally se ejecuta siempre al final sin importar si hubo error o no"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Programo un juego de tres en raya en Python usando una matriz de tres por tres","Represento el tablero como una lista de listas con nueve posiciones inicialmente vacías","Los jugadores se turnan eligiendo una posición indicando fila y columna en cada turno","Después de cada jugada compruebo si hay tres fichas iguales en fila columna o diagonal","El juego termina cuando un jugador gana o cuando todas las posiciones están ocupadas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Descubro las tuplas en Python y entiendo en qué se diferencian de las listas","Una tupla es una secuencia ordenada de elementos que no se puede modificar después","Se crean usando paréntesis en lugar de corchetes y separando los elementos por comas","Son útiles para datos que no deben cambiar como las coordenadas de un punto fijo","Python las procesa más rápido que las listas porque sabe que son inmutables siempre"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Creo un programa que analiza el texto de un libro y cuenta la frecuencia de palabras","Abro el archivo de texto y leo todo su contenido almacenándolo en una variable string","Convierto el texto a minúsculas y elimino los signos de puntuación para normalizar datos","Divido el texto en palabras individuales y uso un diccionario para contar cada aparición","Ordeno el diccionario por frecuencia descendente y muestro las diez palabras más repetidas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Aprendo a usar la biblioteca Matplotlib de Python para crear gráficos estadísticos visuales","Importo matplotlib punto pyplot y creo los datos con listas de valores numéricos","Genero un gráfico de barras con los nombres de los meses y las ventas correspondientes","Personalizo el título los colores las etiquetas de ejes y la leyenda del gráfico","Guardo la imagen del gráfico como archivo PNG y también la muestro en pantalla"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Diseño una API REST sencilla en Python que gestiona una lista de tareas pendientes","Creo las rutas GET para obtener todas las tareas y POST para añadir nuevas","Cada tarea tiene un identificador único un título y un estado de completada o no","La ruta PUT permite actualizar el estado de una tarea existente por su identificador","La ruta DELETE elimina una tarea de la lista usando el identificador como referencia"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Implemento un algoritmo de búsqueda binaria en Python para encontrar elementos rápidamente","La búsqueda binaria solo funciona con listas que ya están ordenadas de menor a mayor","El algoritmo compara el elemento buscado con el valor del centro de la lista actual","Si es menor descarta la mitad superior y si es mayor descarta la inferior","Repite el proceso hasta encontrar el elemento o determinar que no existe en la lista"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Creo un web scraper en Python que extrae títulos de noticias de una página web","Instalo la biblioteca BeautifulSoup que permite analizar documentos HTML de forma sencilla","Uso la biblioteca requests para descargar el código HTML de la página de noticias","Analizo el HTML buscando las etiquetas que contienen los títulos de cada noticia publicada","Guardo los títulos extraídos en un archivo de texto con la fecha de extracción actual"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Aprendo a usar entornos virtuales en Python para aislar las dependencias de cada proyecto","Creo un entorno virtual con el comando python menos m venv seguido del nombre","Activo el entorno virtual ejecutando el script de activación desde la carpeta correspondiente","Instalo las bibliotecas necesarias dentro del entorno sin afectar al sistema global de Python","Genero un archivo requirements punto txt que lista todas las dependencias instaladas del proyecto"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Programo un chatbot básico en Python que responde a preguntas frecuentes del usuario","Creo un diccionario con palabras clave como llaves y respuestas predefinidas como valores","El programa recibe el mensaje del usuario y lo convierte a minúsculas para estandarizar","Busca coincidencias entre las palabras del mensaje y las claves del diccionario de respuestas","Si encuentra una coincidencia muestra la respuesta asociada y si no pide reformular la pregunta"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Descubro los decoradores en Python que permiten modificar el comportamiento de una función","Un decorador es una función que recibe otra función como argumento y la envuelve","Creo un decorador que mide el tiempo de ejecución de cualquier función que decore","Aplico el decorador usando la sintaxis arroba seguida del nombre antes de la definición","Ahora cada vez que llamo a la función decorada también muestra el tiempo empleado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Diseño un sistema de gestión de biblioteca en Python con funciones para cada operación","Creo una función para registrar nuevos libros con título autor e ISBN como datos","Otra función permite buscar libros por título o por autor en la base de datos","La función de préstamo cambia el estado del libro a prestado y registra la fecha","La función de devolución actualiza el estado a disponible y calcula posibles días de retraso"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Aprendo a usar expresiones regulares en Python para buscar patrones en textos complejos","Importo el módulo re que proporciona funciones para trabajar con expresiones regulares eficazmente","Creo un patrón que busca direcciones de correo electrónico en un texto largo dado","Uso la función findall para obtener todas las coincidencias del patrón en el texto","El resultado es una lista con todas las direcciones de correo encontradas automáticamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Creo un programa que genera códigos QR a partir de URLs usando la biblioteca qrcode","Instalo la biblioteca qrcode con pip y también la biblioteca Pillow para imágenes","Escribo la URL que quiero codificar y la paso como argumento a la función generadora","La biblioteca crea una imagen con el código QR que representa la URL proporcionada","Guardo la imagen en formato PNG y compruebo que al escanearla abre la URL correcta"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Implemento el patrón de diseño Modelo Vista Controlador en una aplicación web con Flask","El Modelo gestiona los datos y la lógica de negocio conectándose a la base de datos","La Vista genera las páginas HTML que el usuario ve en su navegador web directamente","El Controlador recibe las peticiones del usuario y coordina la comunicación entre Modelo y Vista","Esta separación de responsabilidades hace que el código sea más organizado y mantenible a largo plazo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Programo un juego de la serpiente en Python usando la biblioteca Pygame para gráficos","Inicializo la ventana del juego con un tamaño de seiscientos por cuatrocientos píxeles","Dibujo la serpiente como una lista de rectángulos verdes que crece al comer comida","La comida aparece en posiciones aleatorias y la serpiente se mueve con las flechas","Si la serpiente choca contra los bordes o contra sí misma el juego termina inmediatamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Aprendo a conectar Python con una base de datos SQLite para almacenar datos persistentes","Importo el módulo sqlite3 que viene incluido en la biblioteca estándar de Python","Creo una conexión a un archivo de base de datos y obtengo un cursor para ejecutar","Ejecuto una sentencia SQL CREATE TABLE para crear la tabla de usuarios con columnas","Inserto registros con INSERT y consulto datos con SELECT mostrando los resultados obtenidos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Creo un programa de cifrado y descifrado de archivos usando la biblioteca cryptography","Instalo la biblioteca con pip e importo el módulo Fernet para cifrado simétrico seguro","Genero una clave secreta única que servirá para cifrar y descifrar los datos protegidos","Leo el contenido del archivo original y lo cifro con la clave generada anteriormente","Guardo el archivo cifrado y compruebo que se puede recuperar el original al descifrar"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Diseño un sistema de autenticación con login y registro usando hash para las contraseñas","Creo la función de registro que recibe usuario y contraseña del nuevo usuario creado","Aplico un hash SHA256 a la contraseña antes de guardarla para que nadie pueda leerla","En el login el usuario introduce su contraseña y el programa calcula su hash correspondiente","Comparo el hash calculado con el hash almacenado y concedo acceso solo si coinciden exactamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Aprendo a usar generadores en Python que producen valores bajo demanda sin ocupar memoria","Un generador es una función que usa yield en lugar de return para devolver valores","Cada vez que se llama produce el siguiente valor sin perder el estado de ejecución","Creo un generador que produce los números de Fibonacci uno a uno cuando se solicitan","Esto ahorra memoria porque no genera toda la secuencia de golpe sino valor por valor"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Programo un sistema de gestión de inventario con interfaz gráfica usando la biblioteca Tkinter","Creo la ventana principal con título y dimensiones adecuadas para mostrar la información","Añado una tabla que muestra los productos con nombre cantidad y precio de cada artículo","Incluyo botones para añadir editar y eliminar productos del inventario con facilidad total","Los datos se guardan en un archivo JSON que se carga automáticamente al abrir el programa"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Descubro los módulos en Python y aprendo a organizar mi código en varios archivos","Un módulo es un archivo Python que contiene funciones clases y variables reutilizables organizadas","Creo un módulo llamado utilidades punto py con funciones de cálculo matemático general","Desde mi programa principal importo las funciones del módulo usando la sentencia import adecuada","Así mantengo el código organizado y puedo reutilizar las funciones en diferentes proyectos futuros"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Creo tests unitarios en Python para verificar que mis funciones producen resultados correctos","Importo el módulo unittest y creo una clase de test que hereda de TestCase base","Escribo un método de test que llama a mi función con datos conocidos de entrada","Uso assertEqual para comprobar que el resultado coincide con el valor esperado exactamente","Ejecuto los tests y el framework me indica si todos pasan o si alguno ha fallado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Implemento un programa que envía correos electrónicos automáticos usando la biblioteca smtplib de Python","Configuro los datos del servidor SMTP con la dirección del servidor y el puerto seguro","Inicio sesión con mi correo electrónico y la contraseña de aplicación generada previamente","Compongo el mensaje con destinatario asunto y cuerpo del correo usando la clase MIMEText","Envío el correo y muestro un mensaje de confirmación indicando que se envió correctamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{3}', '["Diseño un programa que automatiza tareas repetitivas del sistema operativo con Python y os","Importo los módulos os y shutil para gestionar archivos y directorios del sistema operativo","El programa recorre una carpeta y clasifica los archivos por extensión en subcarpetas organizadas","Los archivos PDF van a la carpeta documentos las imágenes a la carpeta fotos automáticamente","Al terminar muestra un resumen con el número de archivos movidos a cada subcarpeta creada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Defino una clase llamada Vehiculo en Python con atributos de marca modelo y velocidad","El constructor init recibe los parámetros y los asigna a los atributos de la instancia","Creo un método acelerar que incrementa la velocidad en un valor dado como parámetro","Creo un método frenar que reduce la velocidad sin permitir que sea menor que cero","Instancio un objeto miCoche de la clase Vehiculo y llamo a sus métodos para probarlo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Aprendo el concepto de herencia en POO creando una jerarquía de clases de animales","Defino la clase base Animal con atributos nombre y sonido y un método hablar genérico","Creo la clase Perro que hereda de Animal y redefine el método hablar con ladrido","Creo la clase Gato que también hereda de Animal pero su método hablar dice miau","Gracias a la herencia ambas clases comparten código común pero tienen comportamientos diferentes"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Implemento el polimorfismo en Python para que objetos diferentes respondan al mismo método","Creo una clase base Figura con un método abstracto calcular area sin implementación concreta","La clase Circulo hereda de Figura e implementa calcular area usando pi por radio cuadrado","La clase Rectangulo hereda de Figura e implementa calcular area multiplicando base por altura","Recorro una lista de figuras mixtas llamando al mismo método y obtengo resultados diferentes"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Aprendo encapsulamiento en POO para proteger los datos internos de una clase de accesos","Defino atributos privados usando doble guion bajo al inicio del nombre de la variable","Creo métodos getter que permiten leer el valor del atributo privado de forma controlada","Creo métodos setter que validan el nuevo valor antes de asignarlo al atributo protegido","Así controlo cómo se accede y se modifica el estado interno del objeto desde fuera"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Diseño una aplicación web completa con frontend en HTML CSS y backend en Python Flask","Creo las plantillas HTML usando el motor de plantillas Jinja2 integrado en Flask fácilmente","Defino las rutas del servidor que procesan formularios y devuelven páginas dinámicas al usuario","Conecto la aplicación a una base de datos SQLite para almacenar los datos de usuarios","Despliego la aplicación en un servidor local y la pruebo accediendo desde el navegador"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Creo una aplicación web con JavaScript que consume una API externa de datos meteorológicos","Escribo una función asíncrona que hace una petición fetch a la API del tiempo actual","La API devuelve los datos en formato JSON con temperatura humedad y descripción del cielo","Parseo la respuesta JSON y extraigo los campos relevantes para mostrarlos al usuario final","Actualizo el DOM de la página con los datos meteorológicos formateados de forma visual atractiva"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Aprendo el patrón de diseño Singleton que garantiza una única instancia de una clase","Defino un atributo de clase privado que almacena la referencia a la única instancia existente","Modifico el constructor para que compruebe si ya existe una instancia antes de crear otra","Si ya existe devuelve la instancia existente en lugar de crear una nueva diferente","Esto es útil para gestores de configuración o conexiones a bases de datos centralizadas compartidas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Implemento un sistema CRUD completo para gestionar una tienda online con Python y Flask","La operación Create permite añadir nuevos productos con nombre descripción precio e imagen","La operación Read muestra todos los productos o uno específico filtrando por su identificador","La operación Update permite modificar los datos de un producto existente en la base","La operación Delete elimina un producto del catálogo tras confirmar la acción del administrador"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Descubro las interfaces y las clases abstractas como mecanismos de diseño orientado a objetos","Una clase abstracta define métodos sin implementación que las subclases deben completar obligatoriamente","Creo la clase abstracta Forma con el método abstracto dibujar que cada subclase implementará","La clase Triangulo implementa dibujar mostrando un triángulo con caracteres de texto en consola","Así garantizo que todas las formas tienen el método dibujar pero cada una lo hace diferente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Creo una aplicación web responsive con CSS Grid y Flexbox para distintos dispositivos","Defino un layout de cuadrícula CSS Grid con tres columnas para pantallas grandes de escritorio","Uso media queries para cambiar a dos columnas en tabletas y una en móviles pequeños","Aplico Flexbox dentro de cada tarjeta para alinear los elementos internos de forma flexible","La página se adapta automáticamente a cualquier tamaño de pantalla manteniendo la legibilidad siempre"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Aprendo a usar Git con ramas para trabajar en equipo sin conflictos de código","Creo una rama nueva llamada feature login para desarrollar el sistema de inicio de sesión","Hago commits regulares en mi rama mientras mis compañeros trabajan en sus propias ramas","Cuando termino mi funcionalidad abro un pull request para que el equipo revise mi código","Tras la revisión fusiono mi rama con la rama principal y el código queda integrado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Diseño un sistema de notificaciones en tiempo real usando WebSockets en una aplicación web","El servidor WebSocket mantiene una conexión abierta con cada cliente conectado a la aplicación","Cuando ocurre un evento importante el servidor envía un mensaje instantáneo a todos los clientes","El cliente recibe el mensaje y actualiza la interfaz mostrando la notificación sin recargar página","Así los usuarios ven las actualizaciones en tiempo real sin necesidad de refrescar el navegador"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Implemento un patrón Observer en Python para que varios objetos reaccionen a cambios automáticamente","Creo una clase Sujeto que mantiene una lista de observadores suscritos a sus cambios","Cuando el estado del Sujeto cambia notifica automáticamente a todos sus observadores registrados","Cada observador implementa un método actualizar que define cómo reaccionar ante la notificación recibida","Así desacoplo los componentes permitiendo que se comuniquen sin conocerse directamente entre sí"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Creo una aplicación de chat en tiempo real usando JavaScript y la biblioteca Socket punto IO","Configuro el servidor Node con Express y Socket punto IO para gestionar conexiones entrantes","Los usuarios se conectan escriben mensajes y el servidor los retransmite a todos los conectados","Cada mensaje muestra el nombre del usuario la hora y el contenido del texto enviado","Cuando alguien se desconecta el servidor avisa al resto de participantes de la sala activa"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Aprendo a documentar mi código usando docstrings siguiendo las convenciones de Python estándar","Cada función tiene un docstring que describe su propósito parámetros y valor de retorno esperado","Cada clase tiene un docstring que explica su responsabilidad y sus atributos principales definidos","Uso la herramienta Sphinx para generar documentación HTML automática a partir de los docstrings","La documentación generada facilita que otros desarrolladores entiendan y usen mi código correctamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Diseño una base de datos relacional con tres tablas relacionadas para una aplicación escolar","Creo la tabla alumnos con campos de identificador nombre apellidos y curso del estudiante","Creo la tabla asignaturas con identificador nombre y número de créditos de cada materia","La tabla matrículas relaciona alumnos con asignaturas usando claves foráneas como referencia cruzada","Escribo consultas SQL con JOIN para obtener las asignaturas matriculadas de cada alumno fácilmente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Implemento autenticación con tokens JWT en una API REST para proteger las rutas privadas","El usuario envía sus credenciales al endpoint de login del servidor de la aplicación","El servidor verifica las credenciales y genera un token JWT firmado con una clave secreta","El cliente guarda el token y lo envía en cada petición posterior como cabecera Authorization","El servidor valida el token en cada petición y solo permite acceso si es válido"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Creo un pipeline de integración continua con GitHub Actions para automatizar el testing completo","Defino un archivo YAML en la carpeta workflows con las instrucciones del pipeline automatizado","Cada vez que hago push a GitHub el pipeline se ejecuta automáticamente en un servidor","Primero instala las dependencias después ejecuta los tests y finalmente verifica el código limpio","Si algún paso falla el pipeline se detiene y me notifica del error por correo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Aprendo el concepto de composición en POO como alternativa a la herencia entre clases","En lugar de heredar creo una clase que contiene instancias de otras clases como atributos","La clase Coche tiene un atributo motor que es una instancia de la clase Motor independiente","También tiene un atributo ruedas que es una lista de cuatro objetos de la clase Rueda","Así construyo objetos complejos combinando objetos más simples de forma flexible y modular"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Diseño una aplicación web progresiva PWA que funciona sin conexión a internet en móviles","Creo un archivo manifest JSON con el nombre el icono y los colores de la aplicación","Registro un Service Worker en JavaScript que intercepta las peticiones de red del navegador","El Service Worker cachea los recursos estáticos para servirlos cuando no hay conexión disponible","La aplicación se puede instalar en el móvil como si fuera una app nativa del dispositivo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Implemento un sistema de control de versiones semántico para mi proyecto de software completo","El número de versión sigue el formato mayor punto menor punto parche como uno punto dos punto tres","Incremento el número de parche cuando corrijo errores sin cambiar la funcionalidad del programa","Incremento el número menor cuando añado nuevas funcionalidades manteniendo compatibilidad hacia atrás","Incremento el número mayor cuando hago cambios que rompen la compatibilidad con versiones anteriores"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Creo un proyecto con arquitectura de microservicios donde cada servicio hace una tarea específica","El servicio de usuarios gestiona el registro y la autenticación de forma completamente independiente","El servicio de productos gestiona el catálogo con su propia base de datos separada e independiente","Los servicios se comunican entre sí mediante peticiones HTTP usando una API REST bien definida","Si un servicio falla los demás siguen funcionando sin interrumpir toda la aplicación completa"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Aprendo a usar contenedores Docker para empaquetar y distribuir mis aplicaciones de forma portable","Escribo un Dockerfile que describe el entorno necesario para ejecutar mi aplicación correctamente","Construyo la imagen Docker ejecutando el comando docker build desde la terminal del sistema","Lanzo un contenedor a partir de la imagen que aísla la aplicación del sistema operativo anfitrión","Puedo compartir la imagen para que otros ejecuten mi aplicación sin instalar nada en su máquina"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Diseño un sistema de permisos basado en roles para una aplicación web con múltiples usuarios","Defino tres roles principales administrador editor y lector con diferentes niveles de acceso","El administrador puede crear modificar y eliminar cualquier contenido de toda la plataforma completa","El editor puede crear y modificar su propio contenido pero no puede eliminar el ajeno","El lector solo puede ver el contenido publicado sin poder modificar ni crear nada nuevo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Implemento un sistema de caché en la aplicación web para mejorar el rendimiento general","Cuando un usuario solicita datos el servidor primero busca en la caché en memoria rápida","Si los datos están en caché los devuelve inmediatamente sin consultar la base de datos","Si no están en caché consulta la base de datos y guarda el resultado en caché","Defino un tiempo de expiración para que la caché se actualice periódicamente con datos frescos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Creo una aplicación web con React que muestra un dashboard de estadísticas en tiempo real","Defino componentes funcionales para cada sección del dashboard como gráficos y tablas de datos","Uso el hook useState para gestionar el estado local de cada componente de la interfaz","Implemento useEffect para cargar los datos desde la API cuando el componente se monta inicialmente","Los componentes se actualizan automáticamente cuando cambian los datos del estado de la aplicación"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('programacion', 'eso', '{4}', '["Aprendo sobre testing de integración para verificar que varios componentes funcionan juntos correctamente","A diferencia de los tests unitarios los tests de integración prueban la interacción entre módulos","Creo un test que verifica que el formulario de registro guarda correctamente en la base","Otro test comprueba que el login devuelve un token válido cuando las credenciales son correctas","Ejecuto todos los tests antes de cada despliegue para asegurar que nada se ha roto"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["La inteligencia artificial intenta que las máquinas imiten cosas que hacen los humanos","Un ejemplo es reconocer caras en las fotos que subimos a las redes sociales","Otro ejemplo es cuando el móvil completa las palabras que estamos escribiendo en mensajes","También cuando un asistente virtual como Alexa responde a nuestras preguntas de voz directamente","La IA está presente en muchas tecnologías que usamos todos los días sin darnos cuenta"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Un chatbot es un programa informático que simula una conversación con una persona real","Funciona analizando las palabras que le escribimos para entender qué estamos preguntando exactamente","Busca en su base de datos la respuesta que mejor encaja con nuestra pregunta formulada","Si no entiende la pregunta nos pide que la reformulemos con otras palabras más claras","Los chatbots se usan en tiendas online bancos y servicios de atención al cliente automatizados"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Los filtros de Instagram usan inteligencia artificial para detectar las partes de tu cara","La cámara del móvil identifica los ojos la nariz y la boca en tiempo real","El algoritmo coloca los efectos digitales exactamente sobre cada parte del rostro detectado automáticamente","Si mueves la cabeza los efectos siguen tu movimiento gracias al seguimiento facial inteligente","Todo esto ocurre en milisegundos para que la experiencia sea fluida y parezca instantánea"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Un sistema de recomendación analiza lo que te gusta para sugerirte cosas nuevas similares","Netflix observa las películas y series que has visto y las que has puntuado","Compara tus gustos con los de millones de usuarios que tienen preferencias parecidas a ti","Selecciona películas que les gustaron a esos usuarios similares pero que tú todavía no has visto","Por eso cada persona ve recomendaciones diferentes adaptadas a sus gustos personales de consumo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Los primeros robots eran máquinas muy simples que solo podían hacer una tarea repetitiva","En los años cincuenta los científicos empezaron a soñar con máquinas que pudieran pensar","Crearon programas que jugaban al ajedrez aunque tardaban horas en decidir cada movimiento inicial","Con el tiempo los ordenadores se hicieron más rápidos y los algoritmos mucho más inteligentes","Hoy la inteligencia artificial puede traducir idiomas conducir coches y crear imágenes artísticas realistas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["El corrector ortográfico del móvil usa inteligencia artificial para mejorar nuestra escritura diaria","Cuando escribo una palabra mal el sistema la compara con su diccionario de palabras correctas","Sugiere la palabra correcta más probable basándose en las letras que he escrito hasta ahora","También aprende las palabras nuevas que uso frecuentemente y las añade a su diccionario personal","Con el tiempo el corrector se adapta a mi forma de escribir y comete menos errores"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Google Maps usa inteligencia artificial para calcular la mejor ruta entre dos puntos cualquiera","Analiza los datos de tráfico en tiempo real recibidos de millones de teléfonos móviles","Predice dónde habrá atascos basándose en patrones históricos de tráfico a esa misma hora","Calcula varias rutas alternativas y elige la que tiene menor tiempo estimado de llegada","Si surge un accidente durante el viaje recalcula automáticamente la ruta para evitar el atasco"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Un asistente virtual como Siri funciona gracias a varias tecnologías de inteligencia artificial combinadas","Primero el reconocimiento de voz convierte las ondas sonoras en texto escrito procesable","Después el procesamiento del lenguaje natural analiza el significado de la frase transcrita","El sistema busca la respuesta más adecuada en sus bases de datos y servicios conectados","Finalmente la síntesis de voz convierte el texto de respuesta en audio hablado para nosotros"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Los videojuegos modernos usan inteligencia artificial para que los enemigos sean más realistas","El programador define reglas de comportamiento para que los personajes no jugadores tomen decisiones","Si el jugador se esconde detrás de un muro el enemigo busca otro camino alternativo","Los enemigos pueden cooperar entre ellos para rodear al jugador y aumentar la dificultad","Esto hace que cada partida sea diferente porque los enemigos reaccionan a nuestras acciones"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Spotify usa IA para crear playlists personalizadas como Discover Weekly cada semana automáticamente","El algoritmo analiza las canciones que escuchas y las que saltas o repites frecuentemente","Compara tus hábitos musicales con los de otros usuarios que tienen gustos similares al tuyo","Selecciona treinta canciones nuevas que probablemente te gustarán basándose en ese análisis profundo","Cada lunes la playlist se renueva con nuevas recomendaciones musicales adaptadas a tus preferencias"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["La IA puede ayudar a los médicos a diagnosticar enfermedades analizando radiografías y escáneres","Un algoritmo entrenado con miles de imágenes médicas aprende a reconocer patrones de enfermedades","El médico sube la radiografía del paciente al sistema de análisis por inteligencia artificial","El sistema señala las zonas sospechosas y sugiere posibles diagnósticos con un porcentaje de confianza","El médico revisa las sugerencias y toma la decisión final combinando la IA con su experiencia"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Las tiendas online usan IA para mostrar precios diferentes según el perfil de cada cliente","El sistema analiza el historial de compras y las búsquedas recientes del usuario registrado","Detecta qué productos le interesan más y cuánto estaría dispuesto a pagar por ellos aproximadamente","Ajusta los precios o muestra ofertas personalizadas para intentar convencer al usuario de comprar","Por eso es importante comparar precios en diferentes dispositivos y momentos antes de comprar algo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Los coches modernos tienen sistemas de asistencia al conductor basados en inteligencia artificial","Las cámaras y sensores del coche detectan las líneas de la carretera y otros vehículos","Si el coche se sale del carril sin usar el intermitente vibra el volante como aviso","El sistema de frenado automático detecta obstáculos y frena si el conductor no reacciona a tiempo","Estos sistemas de seguridad reducen los accidentes de tráfico y salvan muchas vidas cada año"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["La tecnología de reconocimiento de voz ha mejorado mucho gracias a la inteligencia artificial","Antes los ordenadores solo entendían comandos simples y había que hablar muy lento y claro","Ahora pueden entender el habla natural con acentos dialectos y hasta con ruido de fondo","Esto es posible porque los algoritmos se entrenan con millones de horas de grabaciones reales","El reconocimiento de voz se usa en dictado asistentes virtuales y subtítulos automáticos de vídeos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Las redes sociales usan IA para detectar y eliminar contenido inapropiado o peligroso publicado","Un algoritmo analiza las imágenes y los textos que los usuarios publican en la plataforma","Si detecta contenido violento o que incita al odio lo bloquea automáticamente antes de publicarse","También puede detectar cuentas falsas que se crean para difundir noticias falsas o spam masivo","Sin embargo la IA no es perfecta y a veces bloquea contenido legítimo por error involuntario"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Un robot de cocina inteligente usa IA para guiarte paso a paso mientras preparas recetas","Seleccionas la receta en la pantalla táctil y el robot te dice los ingredientes necesarios","Te indica la cantidad exacta de cada ingrediente y el orden en que debes añadirlos","Controla la temperatura y el tiempo de cocción automáticamente para que todo quede perfecto","Si falta algún paso te avisa con una alarma para que no te olvides de nada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Las cámaras de seguridad inteligentes usan IA para detectar situaciones sospechosas en tiempo real","La cámara graba continuamente pero la IA analiza las imágenes buscando comportamientos anormales detectables","Si alguien merodea por una zona restringida fuera de horario el sistema envía una alerta","También puede detectar si alguien deja un paquete abandonado en un lugar público concurrido","El guardia de seguridad recibe la alerta y decide si es una situación real de peligro"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Los subtítulos automáticos de YouTube se generan usando inteligencia artificial de reconocimiento de voz","El sistema escucha el audio del vídeo y lo convierte en texto escrito en tiempo real","Intenta puntuar las frases correctamente y separar los párrafos según las pausas del hablante","Los creadores pueden corregir los errores de los subtítulos automáticos usando el editor de YouTube","Gracias a esta tecnología millones de vídeos son accesibles para personas con discapacidad auditiva"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["La IA de los smartphones agrupa las fotos automáticamente reconociendo las caras de las personas","El teléfono analiza cada foto nueva buscando rostros y comparándolos con los ya conocidos almacenados","Si reconoce una cara la asocia al álbum de esa persona para organizarlas juntas automáticamente","También puede agrupar fotos por lugares usando los datos de ubicación GPS de cada imagen","Así puedes buscar rápidamente todas las fotos de una persona o de un lugar concreto"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{1}', '["Los traductores automáticos como Google Translate usan IA para traducir entre cientos de idiomas","Antes las traducciones se hacían palabra por palabra y el resultado era difícil de entender","Ahora la IA traduce frases completas entendiendo el contexto y el significado global del texto","El sistema se entrena con millones de textos traducidos por humanos profesionales en cada idioma","Aunque ha mejorado mucho todavía comete errores especialmente con expresiones coloquiales y culturales locales"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Los datos son la materia prima fundamental que necesita la inteligencia artificial para funcionar","Sin datos suficientes y de calidad los algoritmos de IA no pueden aprender nada útil","Los datos pueden ser imágenes textos números sonidos o cualquier tipo de información digitalizada disponible","Antes de usar los datos hay que limpiarlos eliminando errores duplicados y valores incompletos encontrados","Cuanto mejores sean los datos de entrenamiento mejores serán los resultados del modelo de IA"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Un algoritmo de clasificación aprende a distinguir entre diferentes categorías de objetos o datos","Para entrenar el clasificador le mostramos miles de ejemplos etiquetados con su categoría correcta","El algoritmo encuentra patrones que diferencian cada categoría analizando los ejemplos de entrenamiento proporcionados","Después de entrenar le damos un ejemplo nuevo que no ha visto nunca antes","El clasificador predice a qué categoría pertenece basándose en los patrones que aprendió anteriormente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["El aprendizaje supervisado es un tipo de entrenamiento donde le damos las respuestas correctas","Preparamos un conjunto de datos donde cada ejemplo tiene una etiqueta con la respuesta correcta","El algoritmo intenta predecir la etiqueta y compara su predicción con la respuesta real conocida","Si se equivoca ajusta sus parámetros internos para acercarse más a la respuesta correcta esperada","Repite este proceso miles de veces hasta que sus predicciones sean suficientemente precisas y fiables"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Un árbol de decisión es un algoritmo que toma decisiones siguiendo preguntas de sí o no","Empieza con una pregunta principal que divide los datos en dos grupos según la respuesta","Cada grupo se subdivide con nuevas preguntas creando ramas como las de un árbol real","Las hojas del árbol representan las decisiones finales o las categorías resultantes del proceso","Este algoritmo es fácil de entender porque podemos visualizar todo el proceso de decisión gráficamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Los datos sesgados pueden hacer que un sistema de IA tome decisiones injustas o discriminatorias","Si entrenamos una IA solo con fotos de personas de piel clara no reconocerá bien otras","El sesgo en los datos refleja los prejuicios de las personas que los recopilaron originalmente","Para evitar sesgos debemos usar datos diversos que representen a todos los grupos de población","Los investigadores revisan constantemente sus modelos para detectar y corregir sesgos antes del despliegue"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["El proceso de entrenar un modelo de IA se parece a cómo aprende un estudiante nuevo","Primero el modelo no sabe nada y sus predicciones son completamente aleatorias e incorrectas siempre","Le mostramos muchos ejemplos y le decimos cuándo acierta y cuándo se equivoca en cada caso","Con cada error el modelo ajusta sus parámetros para mejorar su rendimiento en la próxima vez","Después de muchas iteraciones el modelo aprende y puede predecir correctamente con datos nuevos desconocidos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["La precisión de un modelo de IA se mide comparando sus predicciones con los valores reales","Separamos los datos en dos conjuntos uno para entrenar y otro para evaluar el rendimiento","Entrenamos el modelo solo con el conjunto de entrenamiento sin mostrarle los datos de evaluación","Después pedimos al modelo que prediga los resultados del conjunto de evaluación nunca visto antes","Calculamos el porcentaje de aciertos para saber si el modelo es suficientemente bueno o necesita mejora"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Un dataset o conjunto de datos se organiza en filas y columnas como una hoja de cálculo","Cada fila representa un ejemplo individual como un paciente un producto o una imagen concreta","Cada columna representa una característica o variable como la edad el peso o el color","La última columna suele ser la etiqueta que queremos que el modelo aprenda a predecir","Un buen dataset tiene muchas filas variadas y columnas relevantes para el problema que resolvemos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["El sobreajuste ocurre cuando un modelo memoriza los datos de entrenamiento en lugar de aprender","El modelo tiene un rendimiento excelente con los datos de entrenamiento que ya ha visto","Pero cuando le damos datos nuevos que nunca ha visto sus predicciones son muy malas","Es como un estudiante que memoriza las respuestas del examen de práctica sin entender los conceptos","Para evitarlo usamos técnicas como la validación cruzada y la regularización de los parámetros internos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Los algoritmos de agrupamiento encuentran grupos naturales en los datos sin necesitar etiquetas previas","Este tipo de aprendizaje se llama no supervisado porque nadie le dice las categorías correctas","El algoritmo analiza las características de cada dato y busca similitudes entre ellos automáticamente","Los datos que se parecen más entre sí se agrupan juntos formando clústeres o grupos naturales","Se usa para segmentar clientes agrupar noticias similares o detectar patrones ocultos en datos grandes"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["La matriz de confusión es una herramienta para evaluar cómo de bien clasifica un modelo","Es una tabla que compara las predicciones del modelo con las respuestas reales de cada caso","Los verdaderos positivos son los casos que el modelo predijo correctamente como positivos acertando completamente","Los falsos positivos son casos negativos que el modelo clasificó erróneamente como positivos por error","Analizando la matriz podemos entender en qué tipos de errores falla más nuestro modelo entrenado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Los datos personales que compartimos en internet alimentan los algoritmos de inteligencia artificial continuamente","Cada búsqueda cada like y cada compra genera datos que las empresas almacenan en servidores","Estos datos se usan para entrenar modelos que predicen nuestro comportamiento y preferencias de consumo","La ley de protección de datos obliga a las empresas a informarnos sobre cómo usan nuestros datos","Es importante leer las políticas de privacidad y configurar bien los ajustes de nuestras cuentas online"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Un sistema de recomendación por filtrado colaborativo funciona comparando usuarios con gustos similares entre sí","El sistema crea un perfil de cada usuario basándose en sus valoraciones y comportamiento pasado","Busca otros usuarios que tienen perfiles de gustos muy parecidos al tuyo en la plataforma","Recomienda productos que esos usuarios similares han valorado positivamente pero que tú aún no conoces","Cuantas más valoraciones hagas más preciso será el perfil y mejores serán las recomendaciones recibidas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["La normalización de datos es un paso importante antes de entrenar cualquier modelo de IA","Los datos crudos pueden tener escalas muy diferentes como edad en años y salario en euros","Si no normalizamos el algoritmo dará más importancia a las variables con valores numéricos grandes","La normalización transforma todos los valores a una escala común generalmente entre cero y uno","Así el algoritmo trata todas las variables por igual y aprende patrones más equilibrados y justos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Los chatbots modernos usan procesamiento del lenguaje natural para entender mejor las preguntas humanas","El sistema tokeniza el texto dividiéndolo en palabras o fragmentos más pequeños para analizar","Luego analiza la estructura gramatical para entender la relación entre las palabras de la frase","Identifica la intención del usuario clasificando la pregunta en categorías predefinidas como queja o consulta","Finalmente selecciona la respuesta más apropiada de su base de conocimientos según la intención detectada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["La validación cruzada es una técnica para evaluar modelos de IA de forma más robusta","Dividimos el dataset en cinco partes iguales llamadas pliegues o folds en terminología técnica","Entrenamos el modelo con cuatro partes y evaluamos con la quinta que queda fuera reservada","Repetimos el proceso cinco veces cambiando cada vez la parte que se usa para evaluar","La media de los cinco resultados nos da una estimación más fiable del rendimiento real del modelo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["Los datos estructurados se organizan en tablas con filas y columnas como una base de datos","Los datos no estructurados son textos imágenes vídeos y audios sin formato tabular definido previamente","Los datos semiestructurados como archivos JSON tienen cierta organización pero no encajan en tablas rígidas","La mayoría de datos del mundo son no estructurados lo que supone un reto para la IA","Los avances en deep learning han mejorado mucho la capacidad de procesar datos no estructurados automáticamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["El algoritmo de los vecinos más cercanos clasifica un dato según los ejemplos más parecidos","Cuando recibe un dato nuevo calcula la distancia a todos los datos del conjunto de entrenamiento","Selecciona los K vecinos más cercanos es decir los K datos más parecidos al nuevo","Observa a qué clase pertenecen esos vecinos y asigna la clase mayoritaria al nuevo dato","Es un algoritmo simple pero efectivo que no necesita fase de entrenamiento previa para funcionar"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["La ingeniería de características consiste en seleccionar y crear las variables más útiles para el modelo","No todas las columnas de un dataset son igualmente importantes para predecir el resultado buscado","Algunas variables aportan mucha información relevante mientras que otras solo añaden ruido al modelo","Podemos crear nuevas variables combinando las existentes como calcular el índice de masa corporal total","Elegir bien las características mejora significativamente la precisión y la velocidad de entrenamiento del modelo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{2}', '["El aprendizaje por refuerzo entrena a un agente mediante recompensas y castigos por sus acciones","El agente interactúa con un entorno virtual y toma decisiones basándose en el estado actual","Si la acción produce un buen resultado el agente recibe una recompensa numérica positiva motivadora","Si el resultado es malo recibe un castigo que le enseña a evitar esa acción futura","Con el tiempo el agente aprende la estrategia óptima que maximiza su recompensa total acumulada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["La regresión lineal es un algoritmo que predice un valor numérico continuo a partir de datos","Imagina un gráfico con puntos que representan las horas de estudio y las notas obtenidas","El algoritmo busca la recta que mejor se ajusta a todos esos puntos del gráfico","La pendiente de la recta indica cuánto sube la nota por cada hora adicional de estudio","Con esta recta podemos predecir la nota probable de un alumno según sus horas de estudio"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["Las redes neuronales artificiales se inspiran en el funcionamiento del cerebro humano biológico real","Están formadas por neuronas artificiales organizadas en capas que procesan la información recibida secuencialmente","La capa de entrada recibe los datos la capa oculta los transforma y la de salida responde","Cada conexión entre neuronas tiene un peso que determina la importancia de esa conexión específica","Durante el entrenamiento los pesos se ajustan para que la red produzca las respuestas correctas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["El descenso del gradiente es el método que usan las redes neuronales para aprender optimizando","El algoritmo empieza con pesos aleatorios y calcula el error entre predicción y valor real","Calcula la dirección en la que debe mover los pesos para reducir el error observado","Ajusta los pesos un poco en esa dirección dando un pequeño paso hacia la mejora","Repite el proceso miles de veces hasta que el error sea lo suficientemente pequeño aceptable"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["La regresión logística es un algoritmo de clasificación que predice probabilidades entre cero y uno","A pesar de su nombre no es una regresión sino un clasificador binario de dos categorías","Calcula la probabilidad de que un ejemplo pertenezca a la clase positiva usando una función sigmoide","Si la probabilidad supera un umbral de cero punto cinco clasifica el ejemplo como positivo","Se usa para detectar spam predecir enfermedades o clasificar sentimientos en textos de opiniones escritas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["El procesamiento del lenguaje natural permite a las máquinas entender y generar texto humano real","El primer paso es la tokenización que divide el texto en palabras o subpalabras individuales","Después se eliminan las palabras vacías como artículos y preposiciones que no aportan significado relevante","Se aplica la lematización para reducir cada palabra a su forma base o raíz lingüística","Finalmente se convierte cada palabra en un vector numérico que el modelo puede procesar matemáticamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["Las redes neuronales convolucionales están especializadas en procesar y analizar imágenes de forma eficiente","Las primeras capas detectan características simples como bordes líneas y esquinas de la imagen","Las capas intermedias combinan esas características para reconocer patrones más complejos como texturas y formas","Las capas finales identifican objetos completos como caras coches o animales en la imagen analizada","Este proceso jerárquico imita cómo el cerebro humano procesa la información visual desde lo simple"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["El transfer learning reutiliza un modelo ya entrenado para resolver un problema nuevo diferente rápidamente","Entrenar un modelo desde cero requiere millones de datos y muchas horas de computación intensiva","Un modelo preentrenado como ResNet ya sabe reconocer miles de características visuales genéricas aprendidas","Tomamos ese modelo y lo adaptamos a nuestro problema específico con solo unos pocos datos nuevos","Así conseguimos resultados excelentes con menos datos y mucho menos tiempo de entrenamiento necesario total"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["El random forest es un algoritmo que combina muchos árboles de decisión para mejorar la precisión","Cada árbol se entrena con una muestra aleatoria diferente de los datos de entrenamiento originales","Además cada árbol solo puede usar un subconjunto aleatorio de las características disponibles en los datos","Cuando llega un dato nuevo cada árbol emite su propia predicción de forma independiente y separada","La predicción final es la clase más votada por todos los árboles del bosque aleatorio"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["La función de activación decide si una neurona artificial se activa o no ante una señal","Sin funciones de activación una red neuronal solo podría modelar relaciones lineales simples entre datos","La función ReLU devuelve cero para valores negativos y el mismo valor para los positivos","La función sigmoide comprime cualquier valor de entrada a un rango entre cero y uno","Elegir la función de activación adecuada es crucial para que la red aprenda patrones complejos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["El análisis de sentimientos clasifica textos según la emoción que expresan como positivo o negativo","Se recopilan miles de reseñas de productos etiquetadas con su sentimiento por evaluadores humanos profesionales","El modelo aprende qué palabras y frases se asocian con opiniones positivas negativas o neutras","Después de entrenar puede analizar una reseña nueva y predecir automáticamente su sentimiento predominante expresado","Las empresas usan esta tecnología para monitorizar la opinión pública sobre sus productos y servicios"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["La reducción de dimensionalidad simplifica los datos eliminando variables redundantes o poco informativas del dataset","Cuando un dataset tiene cientos de variables es difícil visualizar y procesar toda la información","El algoritmo PCA encuentra las direcciones principales de variación en los datos multidimensionales originales completos","Proyecta los datos sobre esas direcciones principales reduciendo las variables a unas pocas componentes esenciales","Así podemos visualizar datos complejos en dos o tres dimensiones sin perder demasiada información relevante"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["Las métricas de evaluación nos dicen cómo de bueno es un modelo de clasificación entrenado","La accuracy mide el porcentaje total de predicciones correctas sobre el total de predicciones realizadas","La precisión mide qué porcentaje de las predicciones positivas del modelo son realmente correctas y verdaderas","El recall mide qué porcentaje de los casos positivos reales fueron detectados correctamente por el modelo","El F1-score combina precisión y recall en una sola métrica equilibrada para evaluación global del rendimiento"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["Los sistemas de detección de anomalías identifican datos que se desvían significativamente del patrón normal","Primero el modelo aprende cómo son los datos normales analizando miles de ejemplos típicos regulares","Define los límites de lo que se considera normal basándose en las distribuciones estadísticas observadas","Cuando llega un nuevo dato comprueba si cae dentro de los límites normales establecidos previamente","Si el dato está fuera de los límites lo marca como anomalía para que un humano lo revise"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["La augmentación de datos genera nuevos ejemplos de entrenamiento a partir de los datos existentes","Si tenemos pocas imágenes de entrenamiento el modelo puede no aprender suficientes patrones variados","Aplicamos transformaciones como rotación zoom recorte o cambio de brillo a las imágenes originales existentes","Cada transformación genera una nueva imagen diferente que el modelo puede usar para entrenar adicionalmente","Así multiplicamos el tamaño del dataset sin necesidad de recopilar nuevas imágenes reales manualmente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["Las máquinas de soporte vectorial buscan el hiperplano óptimo que separa dos clases de datos","Imagina puntos de dos colores en un gráfico y una línea que los separa lo mejor posible","El algoritmo busca la línea que maximiza el margen o distancia a los puntos más cercanos","Los puntos más cercanos al hiperplano se llaman vectores de soporte y definen la frontera","Con el truco del kernel puede separar datos que no son linealmente separables en dimensiones mayores"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["El pipeline de machine learning organiza todas las etapas del proceso de forma secuencial ordenada","Empieza con la recopilación y limpieza de los datos necesarios para el entrenamiento del modelo","Sigue con la selección de características la división de datos y la elección del algoritmo adecuado","Continúa con el entrenamiento del modelo y la optimización de sus hiperparámetros de configuración internos","Termina con la evaluación final y el despliegue del modelo en un entorno de producción real"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["La regularización es una técnica que previene el sobreajuste penalizando los modelos demasiado complejos innecesariamente","Añade un término de penalización a la función de error que crece con la complejidad del modelo","La regularización L1 empuja algunos pesos a exactamente cero eliminando características irrelevantes automáticamente del modelo","La regularización L2 reduce el tamaño de todos los pesos distribuyendo la importancia más uniformemente","Elegir el factor de regularización adecuado equilibra la complejidad del modelo con su capacidad de generalización"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["Los word embeddings representan palabras como vectores numéricos que capturan su significado semántico real","Modelos como Word2Vec analizan millones de textos para aprender las relaciones entre las palabras","Las palabras con significados similares tienen vectores cercanos en el espacio multidimensional de representación","Se pueden hacer operaciones matemáticas con los vectores como rey menos hombre más mujer igual reina","Esta representación numérica permite a los modelos de IA entender relaciones semánticas complejas entre palabras"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["La búsqueda de hiperparámetros optimiza la configuración de un modelo para obtener el mejor rendimiento","Los hiperparámetros son valores que el programador elige antes del entrenamiento como la tasa de aprendizaje","La búsqueda en cuadrícula prueba todas las combinaciones posibles de valores de hiperparámetros predefinidos sistemáticamente","La búsqueda aleatoria prueba combinaciones al azar y suele encontrar buenos resultados con menos tiempo","Se evalúa cada combinación usando validación cruzada y se selecciona la que produce el menor error"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{3}', '["Los autoencoders son redes neuronales que aprenden a comprimir y reconstruir datos de entrada originales","La primera mitad de la red el encoder comprime los datos a una representación más pequeña","La segunda mitad el decoder intenta reconstruir los datos originales a partir de la representación comprimida","El modelo se entrena para minimizar la diferencia entre la entrada original y la reconstrucción final","Se usan para reducir dimensionalidad eliminar ruido de imágenes y detectar anomalías en conjuntos de datos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["Los deepfakes son vídeos falsos generados por inteligencia artificial que parecen completamente reales y creíbles","Una red neuronal generativa adversarial analiza miles de imágenes reales de una persona específica","Aprende a generar nuevas imágenes del rostro de esa persona en cualquier posición y expresión","Puede superponer esa cara sobre otro cuerpo en un vídeo creando una falsificación convincente totalmente","Esto plantea serios problemas éticos legales y de desinformación que la sociedad debe abordar urgentemente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["El dilema del tranvía aplicado a los coches autónomos plantea cuestiones éticas muy difíciles de resolver","Un coche autónomo se enfrenta a una situación donde un accidente es inevitable sin escapatoria posible","Debe decidir entre atropellar a un peatón o desviarse poniendo en riesgo a sus propios pasajeros","No hay una respuesta correcta universal porque implica elegir entre dos resultados igualmente trágicos y malos","Los fabricantes deben programar estas decisiones éticas en los algoritmos antes de que los coches circulen"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["Las redes generativas adversariales están formadas por dos redes neuronales que compiten entre sí constantemente","El generador crea datos falsos intentando que sean lo más realistas y convincentes posibles siempre","El discriminador intenta distinguir entre los datos reales y los falsos creados por el generador","Con cada iteración el generador mejora sus falsificaciones y el discriminador afina su capacidad de detección","Al final el generador produce datos tan realistas que el discriminador no puede distinguirlos de los reales"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["La IA explicable busca que los modelos de inteligencia artificial sean transparentes y comprensibles para humanos","Los modelos de deep learning son cajas negras que producen resultados sin explicar su razonamiento interno","Esto es problemático en ámbitos como la medicina o la justicia donde las decisiones deben justificarse","Las técnicas de interpretabilidad muestran qué características de los datos influyeron más en cada predicción","La regulación europea exige que los sistemas de IA que afectan a personas sean explicables y auditables"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["Los transformers son la arquitectura de deep learning que revolucionó el procesamiento del lenguaje natural","Utilizan un mecanismo de atención que permite al modelo enfocarse en las partes relevantes del texto","A diferencia de las redes recurrentes procesan todas las palabras del texto en paralelo simultáneamente","Esto los hace mucho más rápidos de entrenar y capaces de manejar textos muy largos","GPT y BERT son modelos basados en transformers que pueden generar y comprender texto con fluidez"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["La IA en la medicina puede detectar enfermedades en etapas tempranas analizando datos clínicos masivos","Un modelo entrenado con millones de mamografías puede detectar tumores que el ojo humano no ve","Otro modelo analiza el historial del paciente y predice el riesgo de sufrir un infarto futuro","La IA también ayuda a descubrir nuevos fármacos simulando millones de interacciones moleculares por ordenador","Sin embargo el diagnóstico final siempre debe ser validado por un médico que asume la responsabilidad"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["El sesgo algorítmico puede perpetuar y amplificar las desigualdades sociales existentes de forma automática invisible","Un sistema de selección de personal entrenado con datos históricos puede discriminar a ciertos grupos sociales","Si en el pasado se contrataron más hombres la IA aprenderá a preferir candidatos masculinos injustamente","Para detectar el sesgo se analizan las predicciones del modelo desglosadas por género etnia y edad","Corregir el sesgo requiere datos equilibrados auditorías regulares y equipos de desarrollo diversos e inclusivos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["Las redes neuronales recurrentes procesan secuencias de datos donde el orden temporal importa para entender","Tienen conexiones que forman ciclos permitiendo que la información fluya de un paso al siguiente","Son ideales para procesar texto música series temporales y cualquier dato con dependencias temporales claras","El problema del gradiente que desaparece dificulta el aprendizaje de dependencias a largo plazo en secuencias","Las variantes LSTM y GRU resuelven este problema con mecanismos de puertas que controlan el flujo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["La regulación europea de IA clasifica los sistemas según su nivel de riesgo para la sociedad","Los sistemas de riesgo inaceptable como la puntuación social masiva están prohibidos en la Unión Europea","Los de alto riesgo como los usados en educación o justicia necesitan cumplir requisitos estrictos obligatorios","Los de riesgo limitado deben informar al usuario de que están interactuando con un sistema automático","Los de riesgo mínimo como filtros de spam no tienen obligaciones especiales más allá de buenas prácticas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["Los modelos de lenguaje grandes como GPT se entrenan con enormes cantidades de texto de internet","El entrenamiento consiste en predecir la siguiente palabra dado un contexto de palabras anteriores previas","Tras procesar miles de millones de textos el modelo aprende gramática conocimientos y patrones de razonamiento","En la fase de ajuste fino se entrena con ejemplos de diálogo para que siga instrucciones humanas","Estos modelos pueden escribir ensayos traducir idiomas programar y responder preguntas con notable coherencia y fluidez"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["La privacidad diferencial protege los datos personales mientras permite extraer estadísticas útiles del conjunto","Añade ruido matemático controlado a los datos para que ningún individuo pueda ser identificado personalmente","Las estadísticas globales siguen siendo precisas porque el ruido se cancela al agregar muchos datos","Así una empresa puede analizar tendencias generales sin acceder a los datos concretos de cada persona","Apple y Google usan esta técnica para mejorar sus productos sin comprometer la privacidad de usuarios"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["El aprendizaje federado entrena modelos de IA sin centralizar los datos en un solo servidor grande","Cada dispositivo entrena una copia local del modelo con sus propios datos privados almacenados localmente","Solo se envían al servidor central las actualizaciones de los pesos no los datos originales privados","El servidor combina las actualizaciones de todos los dispositivos para mejorar el modelo global compartido","Así los datos personales nunca salen del dispositivo del usuario protegiendo su privacidad efectivamente siempre"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["La IA generativa puede crear contenido nuevo original como imágenes textos música y vídeos realistas","Los modelos de difusión generan imágenes partiendo de ruido aleatorio y eliminando el ruido gradualmente","En cada paso el modelo predice qué ruido debe eliminar para acercarse a la imagen final","Herramientas como DALL-E y Midjourney generan imágenes a partir de descripciones textuales del usuario","Esto plantea debates sobre los derechos de autor y la originalidad del arte generado por máquinas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["La computación cuántica podría revolucionar la inteligencia artificial acelerando ciertos cálculos exponencialmente más rápido","Los bits cuánticos o qubits pueden estar en superposición representando cero y uno simultáneamente a la vez","Esto permite explorar muchas soluciones en paralelo acelerando problemas de optimización y búsqueda enormemente grandes","Algoritmos cuánticos de machine learning podrían entrenar modelos con datasets gigantescos en minutos en vez de días","Sin embargo la tecnología cuántica aún está en fase experimental y faltan años para su uso práctico"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["La IA en el cambio climático ayuda a predecir eventos extremos y optimizar el consumo energético","Modelos de IA analizan datos satelitales para predecir sequías inundaciones y olas de calor futuras","Sistemas inteligentes optimizan la distribución de energía renovable según la predicción meteorológica de cada zona","La IA reduce el consumo energético de edificios ajustando automáticamente calefacción iluminación y aire acondicionado","También ayuda a diseñar materiales más eficientes para paneles solares y baterías mediante simulaciones moleculares"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["Los agentes autónomos de IA pueden planificar y ejecutar tareas complejas descomponiéndolas en pasos simples","El agente recibe un objetivo en lenguaje natural como organizar un viaje a Barcelona completo","Descompone el objetivo en subtareas como buscar vuelos reservar hotel y planificar actividades turísticas diarias","Ejecuta cada subtarea usando herramientas externas como buscadores APIs de reservas y mapas online disponibles","Al final presenta un plan completo al usuario que puede revisar y aprobar antes de confirmar"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["El alineamiento de IA busca que los sistemas inteligentes actúen según los valores humanos deseados","Un modelo de IA podría encontrar formas de cumplir su objetivo que sean dañinas o inesperadas","Por ejemplo maximizar clics podría llevar a recomendar contenido sensacionalista o adictivo a los usuarios","El alineamiento define recompensas y restricciones que guían al modelo hacia comportamientos beneficiosos y seguros","Es uno de los problemas más importantes de la investigación actual en seguridad de inteligencia artificial"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["La IA en la educación personaliza el aprendizaje adaptándose al ritmo y estilo de cada estudiante","Un sistema de tutoría inteligente evalúa los conocimientos del alumno mediante preguntas diagnósticas iniciales breves","Identifica las áreas donde el alumno tiene dificultades y genera ejercicios específicos para reforzar esos temas","Si el alumno progresa rápido el sistema aumenta la dificultad para mantener el desafío motivador activo","Los profesores reciben informes detallados del progreso que les ayudan a intervenir donde más se necesita"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["La IA conversacional multimodal puede procesar y generar texto imágenes audio y vídeo simultáneamente combinados","El usuario puede enviar una foto y preguntar qué se ve en ella usando lenguaje natural","El modelo analiza la imagen identifica los objetos y responde con una descripción textual detallada","También puede generar una imagen a partir de una descripción textual o modificar una imagen existente","Esta capacidad multimodal acerca a la IA a una comprensión más completa del mundo que nos rodea"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('ia', 'eso', '{4}', '["El concepto de singularidad tecnológica describe un futuro hipotético donde la IA supera la inteligencia humana","Algunos expertos predicen que esto podría ocurrir en las próximas décadas del siglo veintiuno actual","Otros consideran que la singularidad es imposible o que está mucho más lejos de lo que pensamos","El debate plantea preguntas éticas sobre si deberíamos crear una IA más inteligente que nosotros mismos","La preparación para estos escenarios futuros requiere reflexión colectiva filosófica científica y política urgente internacional"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Observo un paisaje natural con montañas árboles y un río para dibujarlo al natural","Empiezo haciendo un boceto rápido con líneas suaves de lápiz sin presionar demasiado fuerte","Defino las proporciones generales comparando el tamaño de las montañas con los árboles del primer plano","Añado los detalles progresivamente empezando por las formas grandes y terminando con las texturas pequeñas","Repaso las líneas definitivas con más presión y borro las líneas auxiliares que ya no necesito"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Los colores cálidos son el rojo el naranja y el amarillo que transmiten energía y cercanía","Los colores fríos son el azul el verde y el violeta que sugieren calma y lejanía","En un paisaje los objetos cercanos se pintan con colores cálidos más intensos y saturados","Los objetos lejanos se pintan con colores fríos más claros y apagados simulando la atmósfera","Esta técnica se llama perspectiva atmosférica y crea profundidad en las composiciones pictóricas realizadas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Quiero aprender a dibujar el rostro humano respetando las proporciones básicas de la anatomía facial","Dibujo un óvalo vertical que será la forma base de la cabeza del personaje representado","Trazo una línea horizontal en la mitad del óvalo donde se sitúan los ojos generalmente","La nariz se coloca a mitad de camino entre los ojos y la barbilla del rostro","La boca se sitúa a un tercio de la distancia entre la nariz y la barbilla"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["La simetría es cuando una figura se puede dividir en dos partes iguales y reflejadas","Trazo un eje vertical en el centro de la hoja de papel que actuará de espejo","Dibujo la mitad izquierda de una mariposa con detalle en las alas y las antenas","Mido las distancias de cada punto al eje y las reproduzco a la misma distancia derecha","Al terminar ambos lados son iguales pero reflejados creando una composición simétrica perfecta equilibrada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["El lápiz de grafito tiene diferentes durezas que producen trazos de distinta intensidad y grosor","Los lápices duros como el 2H hacen líneas finas y claras ideales para bocetos previos","Los lápices blandos como el 6B hacen líneas gruesas y oscuras perfectas para sombrear zonas","Para un dibujo completo uso varios lápices empezando con los duros y terminando con los blandos","Difuminar con un papel suave o un difumino crea degradados suaves entre las diferentes tonalidades grises"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Las formas geométricas básicas son el triángulo el cuadrado el círculo y el rectángulo plano","Todas las formas complejas se pueden descomponer en combinaciones de estas formas geométricas simples básicas","Para dibujar un coche empiezo con rectángulos para el cuerpo y círculos para las ruedas","Voy refinando las formas geométricas básicas hasta conseguir el contorno real del objeto que dibujo","Este método de encajar con formas simples facilita mucho el dibujo de objetos complejos y detallados"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["La composición artística es cómo organizamos los elementos dentro del espacio de la obra creada","La regla de los tercios divide la imagen en nueve partes iguales con dos líneas verticales","Colocar los elementos importantes en las intersecciones de estas líneas crea composiciones más dinámicas y atractivas","Centrar el motivo principal transmite estabilidad mientras que descentrarlo genera tensión y movimiento visual interesante","Una buena composición guía la mirada del espectador por toda la obra de forma natural fluida"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Las pinturas rupestres de Altamira son las primeras manifestaciones artísticas de la humanidad conocidas","Los cazadores prehistóricos pintaban animales como bisontes ciervos y caballos en las paredes de cuevas","Usaban pigmentos naturales como el ocre rojo y el carbón negro mezclados con grasa animal","Las figuras aprovechaban las formas naturales de la roca para dar volumen a los cuerpos pintados","Estas pinturas tenían probablemente un significado mágico o ritual relacionado con la caza de animales"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["El degradado es una transición gradual y suave de un tono a otro en el dibujo","Empiezo aplicando el color más oscuro en un extremo presionando fuerte con el lápiz de color","Voy reduciendo la presión progresivamente mientras avanzo hacia el otro extremo de la superficie dibujada","En el centro los tonos se mezclan creando una transición continua sin saltos bruscos de color","Esta técnica es fundamental para representar volumen iluminación y profundidad en cualquier dibujo o pintura"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Los colores complementarios son los que están en posiciones opuestas del círculo cromático pintado","El rojo y el verde son complementarios al igual que el azul y el naranja cálido","Cuando se colocan juntos se intensifican mutuamente creando un contraste visual muy llamativo y potente","Si los mezclamos entre sí se neutralizan produciendo tonos marrones grisáceos y apagados sin saturación","Los artistas usan los complementarios para crear composiciones vibrantes que atraen poderosamente la atención del espectador"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["La técnica del estarcido o stencil permite crear imágenes reproducibles usando plantillas recortadas de cartón","Dibujo el diseño sobre una cartulina gruesa y recorto las zonas que quiero pintar con cuidado","Coloco la plantilla sobre la superficie donde quiero estampar el diseño fijándola con cinta adhesiva","Aplico la pintura con una esponja o brocha dando golpecitos suaves sobre las zonas recortadas abiertas","Al retirar la plantilla aparece el diseño estampado limpio con bordes definidos sobre la superficie pintada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["El claroscuro es una técnica que usa luces y sombras para crear sensación de volumen tridimensional","Identifico de dónde viene la fuente de luz que ilumina el objeto que voy a dibujar","La parte del objeto más cercana a la luz es la zona más clara y luminosa","La parte opuesta a la luz es la zona de sombra propia más oscura del objeto","Debajo del objeto se proyecta la sombra arrojada sobre la superficie donde está apoyado firmemente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["La trama es una técnica de sombreado que usa líneas paralelas para crear diferentes tonalidades","Líneas separadas entre sí crean una zona de tono claro porque se ve el papel blanco","Líneas muy juntas crean una zona de tono oscuro porque cubren casi toda la superficie","La trama cruzada superpone líneas en diferentes direcciones para conseguir tonos todavía más oscuros intensos","Variando la separación y dirección de las líneas puedo crear una amplia gama de grises tonales"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["El arte egipcio representa las figuras humanas siguiendo unas reglas fijas llamadas canon de perfil","La cabeza se dibuja de perfil pero el ojo aparece de frente completo mirando al espectador","Los hombros y el torso se representan de frente para mostrar toda la amplitud del cuerpo","Las piernas y los pies se dibujan de perfil mostrando el paso de una caminata eterna","Este estilo no buscaba el realismo sino mostrar cada parte del cuerpo desde su ángulo más reconocible"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Las ceras blandas son un material artístico que permite crear obras con colores intensos y vibrantes","Aplico la cera presionando sobre el papel creando capas gruesas de color muy saturado brillante","Puedo mezclar colores superponiendo capas de diferentes tonos directamente sobre la superficie del papel","La técnica del esgrafiado consiste en cubrir una capa de color con otra más oscura encima","Después rasco la capa superior con un punzón revelando el color de abajo creando dibujos lineales"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Los mosaicos son obras de arte formadas por pequeñas piezas de colores llamadas teselas unidas","Los romanos decoraban suelos y paredes de sus villas con elaborados mosaicos de temas mitológicos","Cada tesela se coloca individualmente siguiendo un diseño previo dibujado sobre la superficie de base","Los colores y tamaños de las teselas se combinan para crear figuras patrones y escenas completas","Hoy en día podemos crear mosaicos usando trozos de papel cartulina o cerámica como teselas artísticas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["El contraste es la diferencia notable entre dos elementos visuales como claro y oscuro llamativos","Un alto contraste entre figura y fondo hace que el motivo principal destaque con mucha fuerza","Un bajo contraste crea una sensación de suavidad y armonía entre los elementos de la composición","Los artistas usan el contraste de tamaño colocando elementos grandes junto a pequeños para crear interés","El contraste de color combina colores opuestos como negro y blanco o rojo y verde impactantes"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Quiero crear un logotipo sencillo usando solo formas geométricas básicas y dos colores como máximo","Primero pienso en el concepto que quiero transmitir y hago varios bocetos rápidos a lápiz","Selecciono el boceto más claro y lo simplifico eliminando los detalles innecesarios que lo complican","Paso el diseño a limpio usando regla y compás para que las formas sean perfectas geométricamente","Aplico los dos colores elegidos comprobando que el logotipo funciona bien tanto en grande como pequeño"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["La perspectiva cónica es un sistema para representar la profundidad en un dibujo de forma realista","Establezco la línea del horizonte que representa la altura de los ojos del observador mirando","Marco un punto de fuga sobre la línea del horizonte hacia donde convergen todas las líneas","Las líneas paralelas del objeto que van hacia el fondo se dirigen al punto de fuga","Los objetos se hacen más pequeños a medida que se alejan del observador hacia el horizonte"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["El ritmo visual se crea repitiendo elementos de forma regular o alternada en una composición","Dibujo una secuencia de círculos y triángulos que se alternan formando un patrón rítmico visual","Si los repito siempre iguales creo un ritmo uniforme que transmite orden y estabilidad al espectador","Si alterno tamaños grandes y pequeños creo un ritmo alternante más dinámico e interesante visualmente","El ritmo progresivo se consigue aumentando gradualmente el tamaño de los elementos creando sensación de movimiento"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Para hacer un collage necesito papel de revista tijeras pegamento y una cartulina como soporte","Busco en las revistas imágenes y texturas que se relacionen con el tema elegido para recortar","Recorto los trozos con formas variadas creando una colección de materiales con colores y texturas diversos","Compongo los recortes sobre la cartulina probando diferentes distribuciones antes de pegar nada definitivamente fijo","Pego los elementos empezando por el fondo y superponiendo capas hasta completar la composición final artística"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Las letras también son elementos visuales que pueden decorarse y convertirse en obras artísticas creativas","Dibujo mi inicial en tamaño grande con lápiz ocupando casi toda la hoja de papel blanco","Decoro el interior de la letra con patrones geométricos florales o abstractos creando una letra ilustrada","Aplico color usando rotuladores finos para los detalles y gruesos para rellenar las zonas amplias","El resultado es una letra artística única que combina tipografía y diseño gráfico de forma creativa"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["El color tiene tres propiedades fundamentales que son el tono la saturación y el valor luminoso","El tono es el nombre del color como rojo azul o verde que lo identifica básicamente","La saturación indica la pureza del color siendo máxima cuando no tiene mezcla de gris ninguna","El valor se refiere a lo claro u oscuro que es el color respecto al blanco","Modificando estas tres propiedades podemos crear infinitas variaciones a partir de un solo color original"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Realizo un ejercicio de dibujo a ciegas para mejorar mi coordinación ojo-mano al dibujar","Coloco un objeto delante de mí y fijo la mirada en sus contornos sin mirar el papel","Mi mano sigue los contornos del objeto mientras mis ojos recorren sus formas lentamente observando","El resultado no será perfecto pero entrena mi cerebro para conectar lo que veo con lo que dibujo","Con la práctica esta técnica mejora enormemente la capacidad de observación y la fluidez del trazo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Los colores terciarios se obtienen mezclando un color primario con un secundario que está a su lado","Mezclo rojo primario con naranja secundario y obtengo un bonito tono rojo anaranjado terciario intermedio","Mezclo azul primario con verde secundario y consigo un elegante tono azul verdoso turquesa suave","Así completo el círculo cromático con doce colores que incluyen primarios secundarios y terciarios intermedios","Conocer los colores terciarios amplía mi paleta y me permite crear combinaciones cromáticas más ricas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["El arte griego buscaba representar la belleza ideal del cuerpo humano con proporciones perfectas equilibradas","Los escultores griegos crearon un canon de proporciones donde la altura era siete cabezas del modelo","Las esculturas mostraban cuerpos atléticos en posturas naturales con expresiones serenas y equilibradas de armonía","El contrapposto es una postura donde el peso recae sobre una pierna creando una curva natural","El arte griego sentó las bases de la representación realista que influyó en toda la cultura occidental"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Para crear una armonía cromática elijo colores que combinan bien entre sí según el círculo","La armonía de colores análogos usa tres colores vecinos del círculo como azul azul-verde y verde","Esta combinación crea sensaciones de calma y unidad porque los colores son parecidos entre sí naturalmente","La armonía de colores complementarios usa colores opuestos como rojo y verde creando contraste vibrante fuerte","La armonía triádica usa tres colores equidistantes en el círculo como rojo amarillo y azul primarios"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["El bodegón es un género artístico que representa objetos cotidianos inmóviles sobre una mesa ordenados","Selecciono varios objetos como frutas una jarra y un paño de tela con pliegues interesantes","Los coloco formando una composición equilibrada con diferentes alturas formas y texturas variadas y contrastadas","Ilumino la escena con una luz lateral que crea sombras interesantes y resalta los volúmenes redondos","Dibujo el bodegón prestando especial atención a las proporciones los colores y los reflejos de luz"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["La impresión con sellos caseros es una técnica de grabado sencilla muy divertida de realizar","Dibujo un motivo simple en una goma de borrar o en una patata cortada por mitad","Tallo el diseño rebajando las zonas que no quiero que se impriman dejando el motivo relieve","Aplico tinta o pintura sobre la superficie tallada del sello con una brocha o rodillo","Presiono el sello sobre el papel y al levantarlo aparece la imagen impresa repetible muchas veces"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{1}', '["Los pigmentos son sustancias de color que se usan para fabricar pinturas tintes y tintas artísticas","Los pigmentos naturales se obtienen de minerales plantas o insectos como el ocre o el azul añil","Los pigmentos sintéticos se crean artificialmente en laboratorios químicos ofreciendo una gama cromática mucho más amplia","Los pigmentos se mezclan con un aglutinante como aceite agua o acrílico formando diferentes tipos de pintura","Conocer la historia de los pigmentos nos conecta con los artistas que los usaron durante siglos pasados"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["La perspectiva isométrica representa objetos tridimensionales sin punto de fuga manteniendo las proporciones reales constantes","Se trazan tres ejes que forman ángulos de ciento veinte grados entre sí sobre la hoja","Las líneas paralelas del objeto permanecen paralelas en el dibujo sin converger hacia ningún punto","Las medidas se pueden tomar directamente sobre los ejes sin necesidad de reducirlas por profundidad","Es muy utilizada en diseño técnico videojuegos y representación de objetos industriales de forma clara"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["El grabado calcográfico es una técnica de impresión artística que usa planchas de metal preparadas","El artista dibuja sobre una plancha de cobre o zinc usando un buril afilado o ácido","Las líneas grabadas en la plancha retienen la tinta cuando se entinta toda la superficie completa","Se limpia la superficie dejando tinta solo en los surcos grabados más profundos del metal","Al pasar la plancha por la prensa la tinta se transfiere al papel húmedo creando la estampa"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["La fotografía artística utiliza la luz la composición y el encuadre para crear imágenes expresivas","La regla de los tercios ayuda a componer fotografías más dinámicas que simplemente centrar el motivo","La profundidad de campo controla qué parte de la imagen aparece enfocada y cuál aparece borrosa","La luz natural al amanecer o atardecer crea tonos cálidos y sombras largas muy fotogénicas","El ángulo de la cámara picado o contrapicado cambia completamente la percepción del sujeto fotografiado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["El movimiento impresionista revolucionó la pintura al capturar la luz y el color del instante","Los pintores impresionistas salían a pintar al aire libre para captar la luz natural cambiante","Usaban pinceladas sueltas y rápidas que no se mezclaban en la paleta sino en el lienzo","Los colores puros se yuxtaponían para que el ojo del espectador los mezclara a distancia","Monet Renoir y Degas son algunos de los artistas más representativos de este movimiento artístico"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["El diseño de un cartel publicitario sigue principios de comunicación visual clara y directa efectiva","Primero defino el mensaje principal que quiero transmitir y el público objetivo al que me dirijo","Elijo una imagen potente que atraiga la atención y se relacione directamente con el mensaje central","Selecciono una tipografía legible y un eslogan breve que resuma la idea en pocas palabras clave","Organizo todos los elementos siguiendo una jerarquía visual donde lo más importante se ve primero claramente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["Las vanguardias artísticas del siglo veinte rompieron con las normas tradicionales de representación pictórica clásica","El cubismo descomponía los objetos en formas geométricas mostrando varias perspectivas simultáneamente en un solo cuadro","El surrealismo exploraba el mundo de los sueños y el subconsciente creando imágenes fantásticas e ilógicas","El expresionismo abstracto abandonó la figuración para expresar emociones puras mediante el color y el gesto","Cada movimiento de vanguardia abrió nuevos caminos artísticos que siguen influyendo en el arte actual contemporáneo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["La xilografía es una técnica de grabado en relieve que utiliza planchas de madera como matriz","Dibujo el diseño sobre la superficie lisa de una plancha de madera blanda como el contrachapado","Tallo con gubias las zonas que quiero que queden en blanco rebajando la superficie de madera","Las zonas no talladas que quedan en relieve son las que recibirán la tinta de impresión","Entinto el relieve con un rodillo presiono el papel encima y obtengo una estampa xilográfica artística"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["El color en la publicidad se usa estratégicamente para provocar emociones específicas en el consumidor","El rojo transmite urgencia y pasión por eso se usa en ofertas y rebajas comerciales frecuentemente","El azul transmite confianza y seguridad razón por la cual lo usan bancos y empresas tecnológicas","El verde se asocia con la naturaleza y la salud siendo frecuente en productos ecológicos y orgánicos","Conocer la psicología del color nos ayuda a crear diseños más efectivos y a ser consumidores críticos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["La escultura en arcilla permite modelar formas tridimensionales con las manos directamente sobre el material","Preparo la arcilla amasándola para eliminar burbujas de aire que podrían hacer estallar la pieza","Modelo la forma general primero usando mis manos y después refinando con herramientas de modelado","Creo los detalles como texturas y relieves usando estecas palillos y sellos sobre la superficie húmeda","Dejo secar la pieza lentamente y la meto en el horno cerámico para que endurezca definitivamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{2}', '["El arte pop utilizó imágenes de la cultura popular y el consumo como material artístico nuevo","Andy Warhol transformó productos comerciales como latas de sopa en iconos del arte contemporáneo universal","Roy Lichtenstein se inspiró en los cómics ampliando las viñetas a gran escala con puntos benday","Los artistas pop usaban colores planos y brillantes tomados de la publicidad y los medios masivos","Este movimiento cuestionó la frontera entre el arte culto y la cultura popular de masas cotidiana"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["El sistema diédrico representa objetos tridimensionales mediante sus proyecciones ortogonales sobre dos planos perpendiculares","Se proyecta el objeto sobre el plano horizontal obteniendo la vista superior llamada planta del objeto","Se proyecta sobre el plano vertical obteniendo la vista frontal llamada alzado de la pieza representada","La línea de tierra separa ambas proyecciones y sirve como referencia para las medidas de altura","Con estas dos vistas y a veces una tercera lateral se define completamente la forma del objeto"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["El diseño gráfico combina tipografía imagen y color para comunicar mensajes visuales de forma efectiva","El proceso empieza con un briefing donde el cliente explica qué necesita comunicar a su audiencia","El diseñador investiga el público objetivo y la competencia antes de generar ideas conceptuales creativas","Crea varios bocetos digitales explorando diferentes composiciones tipografías y paletas cromáticas posibles para el proyecto","Tras la revisión con el cliente refina el diseño seleccionado hasta obtener la pieza final publicable"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["La proporción áurea es una relación matemática que aparece en la naturaleza y en el arte","Se expresa con el número phi que equivale aproximadamente a uno coma seiscientos dieciocho irracional","Un rectángulo áureo tiene sus lados en proporción áurea y se puede subdividir infinitamente de igual forma","Los griegos usaban esta proporción en la arquitectura del Partenón para lograr armonía visual perfecta equilibrada","Muchos artistas como Leonardo da Vinci aplicaron la proporción áurea en la composición de sus pinturas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["El proceso de diseño industrial sigue etapas desde la idea inicial hasta el producto fabricado final","Se identifica una necesidad del usuario y se investigan los productos existentes que intentan resolverla","Se generan múltiples ideas mediante bocetos rápidos y se selecciona la más viable técnica y estéticamente","Se crea un prototipo o maqueta a escala para probar la forma la ergonomía y el funcionamiento","Se realizan las pruebas necesarias y se elaboran los planos técnicos definitivos para la fabricación industrial"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["La tipografía es el arte de diseñar y componer textos de forma legible expresiva y funcional","Las fuentes serif como Times tienen remates pequeños en los extremos de cada letra dibujada","Las fuentes sans-serif como Arial no tienen remates y ofrecen un aspecto moderno limpio y minimalista","El tamaño el interlineado y el espaciado entre letras afectan a la legibilidad del texto escrito","Elegir la tipografía adecuada es fundamental porque transmite personalidad y facilita la lectura del mensaje"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["El Renacimiento italiano revolucionó el arte occidental recuperando los ideales de belleza clásica grecorromana perdidos","Los artistas estudiaron la anatomía humana la perspectiva matemática y la proporción para lograr obras realistas","Leonardo da Vinci pintó La Gioconda usando la técnica del sfumato que difumina los contornos suavemente","Miguel Ángel esculpió el David como símbolo de la perfección del cuerpo humano ideal renacentista","Rafael pintó La Escuela de Atenas dominando la perspectiva central para crear un espacio arquitectónico profundo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["La identidad corporativa es el conjunto de elementos visuales que representan a una empresa o marca","El logotipo es el símbolo gráfico que identifica a la marca de forma inmediata y reconocible","La paleta de colores corporativa define los tonos exactos que la marca usa en todas sus comunicaciones","La tipografía corporativa se selecciona para transmitir los valores de la marca como modernidad o tradición","El manual de identidad corporativa documenta todas las normas de uso para mantener la coherencia visual"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["La acotación en dibujo técnico indica las medidas reales del objeto representado de forma normalizada","Las cotas se componen de líneas de cota líneas auxiliares y el número que indica la medida","Las líneas de cota se trazan paralelas a la dimensión que miden con flechas en los extremos","Las líneas auxiliares parten del objeto y se prolongan más allá de la línea de cota","El número de cota se coloca centrado sobre la línea indicando la medida real en milímetros siempre"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["El Barroco es un estilo artístico que buscaba impresionar al espectador con dramatismo y grandiosidad emocional","Caravaggio revolucionó la pintura usando un contraste extremo entre luces y sombras llamado tenebrismo pictórico","Velázquez pintó Las Meninas combinando realismo perspectiva compleja y un juego de miradas entre personajes fascinante","Bernini creó esculturas de mármol con tal realismo que las telas parecen flotar y la piel respirar","La arquitectura barroca usaba fachadas curvas columnas salomónicas y abundante decoración para impresionar a los fieles"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{3}', '["El packaging o diseño de envases combina funcionalidad protección del producto y atractivo visual comercial estratégico","El diseñador estudia las dimensiones del producto y el material más adecuado para el envase contenedor","Crea el desarrollo plano del envase que es la plantilla que se plegará para formar la caja","Aplica el diseño gráfico con la marca el nombre del producto y la información legal obligatoria","Monta un prototipo del envase para verificar que el producto encaja bien y el diseño funciona correctamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["El diseño web combina principios de diseño gráfico con la interactividad propia del medio digital","Se empieza creando wireframes que son esquemas básicos de la estructura y distribución de contenidos","Después se diseñan los mockups con colores tipografías imágenes y todos los detalles visuales definitivos","Se programa el diseño usando HTML CSS y JavaScript para hacerlo interactivo y funcional en navegadores","Se realizan pruebas de usabilidad con usuarios reales para comprobar que la navegación es intuitiva y clara"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["El arte conceptual prioriza la idea sobre la ejecución material de la obra de arte creada","Marcel Duchamp presentó un urinario como obra de arte cuestionando qué define al arte como tal","Los artistas conceptuales usan textos instrucciones fotografías o acciones como medios de expresión artística válidos","La obra de arte no necesita ser un objeto físico bello sino transmitir un concepto o reflexión","Este enfoque abrió el camino al arte contemporáneo donde la idea prevalece sobre la técnica manual"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["La animación digital crea la ilusión de movimiento mostrando imágenes fijas en sucesión rápida continua","El proceso empieza con un guion que describe la historia los personajes y las escenas planeadas","Se crean storyboards que son viñetas dibujadas que planifican cada escena clave de la animación completa","Se diseñan los personajes y se crean los fotogramas clave que definen los movimientos principales visibles","Los fotogramas intermedios se generan por interpolación completando el movimiento fluido entre las poses principales definidas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["La perspectiva cónica con dos puntos de fuga representa objetos vistos desde una esquina angular","Trazo la línea del horizonte y coloco dos puntos de fuga separados en sus extremos opuestos","Las aristas verticales del objeto se dibujan como líneas verticales paralelas entre sí sobre el papel","Las aristas horizontales que van hacia la derecha convergen hacia el punto de fuga derecho indicado","Las aristas horizontales que van hacia la izquierda convergen hacia el punto de fuga izquierdo señalado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["El street art o arte urbano transforma el espacio público en un lienzo artístico accesible universal","Los artistas urbanos utilizan técnicas como el grafiti el mural los stencils y las instalaciones temporales","Banksy es un artista anónimo cuyas obras combinan humor crítica social y un estilo visual reconocible","El debate sobre el street art cuestiona si es vandalismo o una forma legítima de expresión artística","Muchas ciudades han integrado el arte urbano como elemento de revitalización cultural de barrios degradados abandonados"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["El modelado tridimensional digital permite crear objetos virtuales con formas complejas usando software especializado avanzado","Se empieza con una forma básica como un cubo o esfera que se modifica progresivamente con herramientas","Las herramientas de extrusión permiten sacar volumen de las caras del objeto para crear protuberancias nuevas","Se aplican materiales y texturas digitales que simulan el aspecto real de madera metal o tela","Finalmente se ilumina la escena y se renderiza generando una imagen fotorrealista del objeto tridimensional creado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["El arte cinético crea obras que incorporan movimiento real o aparente como parte esencial de expresión","Alexander Calder inventó los móviles esculturas colgantes cuyos elementos se mueven con las corrientes de aire","Jesús Rafael Soto creó penetrables instalaciones de hilos colgantes que el espectador puede atravesar físicamente participando","El op art de Vasarely usa patrones geométricos que crean ilusiones ópticas de movimiento y vibración visual","Estas corrientes artísticas cuestionaron la idea del arte estático e incorporaron al espectador como parte activa"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["La infografía combina texto datos e imágenes para comunicar información compleja de forma visual clara","Se analizan los datos que queremos comunicar y se identifican los puntos clave más importantes relevantes","Se elige el tipo de gráfico más adecuado como barras circular líneas o diagrama de flujo","Se diseña la jerarquía visual usando tamaño color y posición para guiar la lectura del espectador","Se integran iconos ilustraciones y texto breve para crear una pieza informativa atractiva y fácil de entender"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["La arquitectura sostenible integra principios de diseño que minimizan el impacto ambiental de los edificios construidos","Se orienta el edificio para aprovechar al máximo la luz solar natural reduciendo el consumo eléctrico","Se eligen materiales ecológicos reciclados o de bajo impacto como la madera certificada y el bambú","Se diseñan sistemas de ventilación natural que reducen la necesidad de aire acondicionado en verano caluroso","Se instalan paneles solares y sistemas de recogida de agua de lluvia para la autosuficiencia energética"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('plastica', 'eso', '{4}', '["El videoarte utiliza la imagen en movimiento como medio de expresión artística diferente al cine comercial","Los artistas experimentan con la duración la repetición la velocidad y la manipulación digital de las imágenes","Nam June Paik fue pionero del videoarte usando monitores de televisión como material escultórico en instalaciones","Bill Viola crea obras contemplativas con vídeos en cámara lenta que exploran temas como la vida y muerte","El videoarte se exhibe en museos galerías y espacios públicos transformando la experiencia del espectador contemporáneo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["El proceso tecnológico comienza cuando identificamos un problema o necesidad que queremos resolver de forma práctica","Investigamos soluciones existentes y recopilamos información útil sobre materiales y técnicas disponibles para el proyecto","Diseñamos una solución creando bocetos y planos técnicos con las medidas y los materiales necesarios","Construimos el prototipo siguiendo los planos y usando las herramientas adecuadas de forma segura en taller","Evaluamos si el resultado funciona correctamente y si se puede mejorar basándonos en las pruebas realizadas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Los plásticos se fabrican a partir del petróleo mediante procesos químicos industriales de polimerización controlada","El polietileno es un plástico ligero y flexible que se usa para fabricar bolsas y envases comunes","El PVC es un plástico rígido y resistente utilizado en tuberías marcos de ventanas y canalones","El poliestireno expandido conocido como corcho blanco es un excelente aislante térmico muy ligero y barato","Los plásticos tardan cientos de años en degradarse por eso es fundamental reciclarlos correctamente siempre"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Para construir una maqueta de un puente necesito planificar los materiales y las herramientas adecuadas","Dibujo el diseño del puente a escala indicando las medidas de cada pieza de madera necesaria","Corto las piezas de madera de balsa con el cúter siguiendo las líneas marcadas con precisión","Uno las piezas con cola blanca y refuerzo las uniones con escuadras triangulares de cartón resistente","Dejo secar la estructura y pruebo su resistencia colocando pesos encima para verificar su estabilidad final"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Las herramientas de medida nos permiten obtener las dimensiones exactas de los objetos que trabajamos","La regla graduada mide longitudes rectas con precisión de un milímetro en distancias cortas pequeñas","El metro de cinta flexible permite medir longitudes mayores y también superficies curvas de forma cómoda","El calibre o pie de rey mide con precisión de décima de milímetro espesores y diámetros pequeños","El transportador de ángulos mide la abertura de los ángulos en grados desde cero hasta ciento ochenta"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Las estructuras triangulares son las más resistentes porque no se deforman cuando se les aplica fuerza","Un cuadrado articulado se deforma fácilmente convirtiéndose en un rombo si empujamos una de sus esquinas","Si añadimos una diagonal al cuadrado lo dividimos en dos triángulos y ya no se deforma","Las cerchas de los tejados usan triángulos para soportar el peso de las tejas sin deformarse","Los puentes de celosía combinan muchos triángulos metálicos para crear estructuras ligeras pero extremadamente resistentes a cargas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["El reciclaje de materiales sigue un proceso que va desde la recogida hasta la fabricación nueva","Los ciudadanos separan los residuos en contenedores de diferentes colores según el tipo de material reciclable","Los camiones recogen los contenedores y llevan los materiales a las plantas de selección y clasificación","En la planta se separan los materiales por tipo usando cintas magnéticas y clasificación manual experta","Los materiales seleccionados se trituran lavan y procesan para convertirse en materia prima de nuevos productos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["El papel se fabrica a partir de la celulosa que se obtiene de la madera de árboles","Los troncos se descortezan y se trituran hasta convertirlos en una pasta de fibras de celulosa","La pasta se mezcla con agua y se extiende en una capa fina sobre una malla metálica","Se prensa para eliminar el agua y se seca pasando entre rodillos calientes a alta temperatura","El resultado es una lámina continua de papel que se enrolla en bobinas gigantes para su distribución"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Las herramientas de corte se utilizan para separar y dar forma a los materiales del taller","La sierra de arco corta metales y plásticos duros con una hoja dentada tensa en el marco","La segueta o sierra de marquetería corta madera fina y contrachapado siguiendo líneas curvas con precisión","El cúter corta cartón papel y plásticos finos deslizando su cuchilla afilada por la línea marcada","Las tijeras de hojalatero cortan láminas finas de metal como hojalata aluminio y cobre sin dificultad"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Los materiales se clasifican según su origen en naturales artificiales y sintéticos por su procedencia","Los materiales naturales se obtienen directamente de la naturaleza como la madera la lana y el algodón","Los materiales artificiales se fabrican transformando materiales naturales como el papel el vidrio y la cerámica","Los materiales sintéticos se crean mediante reacciones químicas a partir del petróleo como los plásticos comunes","Cada tipo de material tiene propiedades diferentes que lo hacen adecuado para usos específicos determinados concretos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Un circuito eléctrico básico necesita cuatro elementos fundamentales para funcionar correctamente sin interrupciones ni fallos","La pila o batería es el generador que proporciona la energía eléctrica al circuito como fuente principal","Los cables conductores transportan la corriente eléctrica desde la pila hasta los demás componentes conectados","El interruptor abre o cierra el circuito permitiendo controlar el paso de la corriente eléctrica fácilmente","La bombilla es el receptor que transforma la energía eléctrica en luz y calor al funcionar"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Las propiedades mecánicas de los materiales determinan cómo se comportan cuando se les aplica una fuerza","La dureza es la resistencia que ofrece un material a ser rayado por otro material más duro","La elasticidad permite que un material recupere su forma original después de deformarse por una fuerza","La plasticidad hace que un material se deforme permanentemente sin romperse cuando se le aplica fuerza","La fragilidad provoca que un material se rompa bruscamente sin deformarse cuando recibe un golpe fuerte"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Las uniones de materiales pueden ser fijas o desmontables según las necesidades del proyecto diseñado","Las uniones fijas como el pegado o la soldadura no permiten separar las piezas sin romperlas","Las uniones desmontables como los tornillos y las tuercas permiten desarmar y volver a montar fácilmente","Los clavos son uniones semifijas que se pueden extraer pero dejan marca en el material perforado","Elegir el tipo de unión adecuado depende del material la función y si necesitamos desmontar después"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["La memoria de un ordenador almacena los datos y las instrucciones que el procesador necesita ejecutar","La memoria RAM es rápida pero temporal y se borra cuando apagamos el ordenador completamente siempre","El disco duro almacena los datos de forma permanente incluso cuando el ordenador está apagado totalmente","Los discos SSD son más rápidos que los discos duros tradicionales porque no tienen partes mecánicas","La memoria USB es un dispositivo portátil que permite transportar archivos de un ordenador a otro fácilmente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Las normas de seguridad en el taller protegen nuestra integridad física mientras trabajamos con herramientas","Siempre debemos usar gafas de protección cuando cortamos lijamos o manipulamos materiales que pueden saltar","Las herramientas cortantes se sujetan con firmeza y se corta siempre en dirección contraria al cuerpo","El taller debe estar ordenado y limpio para evitar tropiezos y accidentes con materiales en el suelo","Nunca debemos usar una herramienta sin que el profesor nos haya explicado su uso correcto previamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Los textiles son materiales flexibles formados por fibras entrelazadas que se usan para confeccionar tejidos","Las fibras naturales como el algodón la lana y la seda provienen de plantas y animales directamente","Las fibras sintéticas como el poliéster y el nailon se fabrican mediante procesos químicos industriales controlados","Para crear un tejido las fibras se hilan formando hilos que luego se entretejen en telares","Las propiedades del tejido como suavidad resistencia y transpirabilidad dependen del tipo de fibra utilizada principalmente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Un sistema operativo es el programa fundamental que gestiona todos los recursos del ordenador automáticamente","Cuando enciendo el ordenador el sistema operativo se carga en la memoria RAM desde el disco","Gestiona la comunicación entre el hardware como el teclado y el software como los programas aplicaciones","Permite abrir varias ventanas y programas a la vez repartiendo el tiempo del procesador entre ellos","Windows Linux y macOS son los tres sistemas operativos más usados en ordenadores personales de escritorio"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Los esfuerzos son las fuerzas internas que aparecen dentro de un material cuando se le aplica carga","La tracción estira el material como cuando tiramos de una cuerda con fuerza desde ambos extremos","La compresión aplasta el material como el peso que soportan los pilares de un edificio grande","La flexión curva el material como una estantería que se comba por el peso de libros","La torsión retuerce el material como cuando escurrimos una toalla mojada girando los extremos en direcciones contrarias"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["El vidrio se fabrica fundiendo arena de sílice a temperaturas muy elevadas superiores a mil grados","Se mezcla la arena con sosa y cal que ayudan a reducir la temperatura de fusión necesaria","La mezcla fundida se moldea soplándola estirándola o vertiéndola en moldes según la forma deseada final","Al enfriarse lentamente el material se solidifica formando un sólido transparente duro y frágil a golpes","El vidrio es reciclable infinitas veces sin perder calidad lo que lo convierte en material muy sostenible"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["La evolución tecnológica ha transformado la forma en que los humanos vivimos trabajamos y nos comunicamos","Las herramientas de piedra fueron las primeras tecnologías que permitieron a los humanos cazar y construir","La invención de la rueda facilitó el transporte de mercancías pesadas a largas distancias de forma eficiente","La máquina de vapor desencadenó la revolución industrial cambiando la producción artesanal por la industrial masiva","Internet y los smartphones han conectado a miles de millones de personas transformando la sociedad actual globalmente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Los periféricos de entrada permiten al usuario introducir datos e instrucciones en el ordenador fácilmente","El teclado es el periférico de entrada más común que permite escribir textos y dar comandos","El ratón controla un puntero en pantalla y permite seleccionar y arrastrar elementos gráficos visualmente","El escáner digitaliza documentos y fotografías en papel convirtiéndolos en archivos de imagen dentro del ordenador","La webcam captura vídeo en tiempo real y se usa para videoconferencias y grabaciones de vídeo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Las cerámicas se fabrican a partir de arcilla que se moldea y se cuece a alta temperatura","El alfarero amasa la arcilla para hacerla homogénea y eliminar las burbujas de aire internas","Moldea la pieza en el torno dándole forma con las manos mientras la arcilla gira rápidamente","La pieza moldeada se deja secar lentamente al aire para que pierda humedad sin agrietarse","Después se introduce en el horno a más de mil grados donde se endurece definitivamente para siempre"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["La hoja de cálculo es una herramienta informática que organiza datos en filas y columnas estructuradas","Cada celda se identifica por una letra de columna y un número de fila como coordenadas exactas","Puedo introducir números textos y fórmulas que realizan cálculos automáticos con los datos de otras celdas","La función SUMA calcula automáticamente el total de un rango de celdas que le indico como argumento","Con los datos de la hoja puedo crear gráficos de barras circulares o de líneas visualmente claros"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["El acabado superficial de un proyecto de tecnología mejora su aspecto y protege el material usado","Primero lijo la superficie con lija gruesa para eliminar las imperfecciones y astillas más grandes","Después uso lija fina para dejar la superficie completamente lisa y suave al tacto sin rugosidades","Aplico una primera capa de imprimación o sellador que prepara la superficie para recibir la pintura","Finalmente pinto con esmalte o barniz aplicando capas finas y dejando secar entre cada una completamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Los metales ferrosos contienen hierro como componente principal y son los más utilizados en la industria","El acero es una aleación de hierro y carbono que combina dureza resistencia y cierta elasticidad útil","El hierro fundido contiene más carbono que el acero lo que lo hace duro pero frágil siempre","Los metales ferrosos se oxidan fácilmente al contacto con el agua y el aire húmedo ambiental","Para protegerlos de la oxidación se pintan se galvanizan o se recubren con capas de otros metales"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Los metales no ferrosos no contienen hierro y presentan propiedades muy variadas según el metal concreto","El aluminio es ligero resistente a la oxidación y fácil de moldear siendo ideal para latas y marcos","El cobre es un excelente conductor eléctrico y térmico usado en cables tuberías y componentes electrónicos variados","El bronce es una aleación de cobre y estaño conocida desde la antigüedad por su dureza resistente","El latón es una aleación de cobre y zinc que se usa en grifería cerraduras e instrumentos musicales"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Para fabricar un objeto tecnológico primero hay que planificar todas las operaciones necesarias de forma ordenada","La hoja de operaciones es un documento que describe paso a paso cómo se fabricará el objeto","Cada operación incluye la descripción de la tarea las herramientas necesarias y el tiempo estimado de ejecución","Siguiendo la hoja de operaciones evitamos olvidar pasos importantes y trabajamos de forma más eficiente organizada","Al final comparamos el tiempo real invertido con el estimado para mejorar en futuros proyectos similares"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Los enlaces móviles son uniones que permiten cierto movimiento entre las piezas que unen sin soltarse","La bisagra permite el giro de una puerta o una tapa sobre un eje fijo horizontal","Las rótulas permiten movimiento en varias direcciones como las que tenemos en nuestras propias articulaciones corporales","Los rodamientos facilitan el giro de un eje reduciendo la fricción entre las piezas en contacto","Estos enlaces móviles son fundamentales en mecanismos máquinas y estructuras articuladas de todo tipo posible"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["El procesador de textos es una herramienta informática fundamental para crear y editar documentos escritos profesionales","Permite cambiar el tipo de letra el tamaño el color y el formato del texto fácilmente","Tiene funciones de corrección ortográfica que subrayan los errores para que podamos corregirlos antes de imprimir","Puedo insertar imágenes tablas gráficos y encabezados que enriquecen el documento y lo hacen más profesional","Al terminar guardo el documento en el formato adecuado y puedo imprimirlo o compartirlo por correo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["El dibujo técnico utiliza normas internacionales para representar objetos de forma precisa y sin ambigüedades","Cada tipo de línea tiene un significado específico como las continuas para aristas visibles o discontinuas ocultas","La escala indica la relación entre las medidas del dibujo y las medidas reales del objeto representado","Los planos pueden estar a escala uno a uno natural ampliados o reducidos según el tamaño necesario","Siguiendo estas normas cualquier técnico del mundo puede interpretar correctamente un plano sin confusiones posibles"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{1}', '["Las herramientas de percusión se usan para golpear materiales con el objetivo de darles forma o unirlos","El martillo es la herramienta de percusión más conocida y se usa para clavar clavos golpeando firmemente","Hay martillos de diferentes tamaños y pesos según el tipo de trabajo que vayamos a realizar","El mazo de madera o goma se usa cuando no queremos marcar ni dañar la superficie golpeada","Siempre debemos sujetar bien la herramienta y golpear con firmeza pero sin exceso de fuerza descontrolada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["Los mecanismos de transmisión del movimiento transfieren el giro de un eje a otro diferente conectado","Las poleas son ruedas con una ranura por donde pasa una correa que conecta dos ejes","Si una polea grande mueve a una pequeña la pequeña gira más rápido pero con menos fuerza","Los engranajes son ruedas dentadas que encajan entre sí transmitiendo el movimiento con mayor precisión mecánica","La relación de transmisión indica cuántas vueltas da la rueda conducida por cada vuelta de la motriz"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["La ley de Ohm establece la relación entre voltaje intensidad y resistencia en un circuito eléctrico","El voltaje medido en voltios es la fuerza que empuja a los electrones por el circuito","La intensidad medida en amperios es la cantidad de electrones que circulan por segundo por el cable","La resistencia medida en ohmios es la oposición que el material ofrece al paso de corriente","La fórmula dice que el voltaje es igual a la intensidad multiplicada por la resistencia siempre"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["Un circuito en serie conecta todos los componentes uno detrás de otro en un solo camino","La corriente eléctrica es la misma en todos los puntos del circuito porque solo hay un camino","Si una bombilla se funde el circuito se interrumpe y todas las demás dejan de funcionar","El voltaje total se reparte entre todos los componentes proporcionalmente a su resistencia individual de cada uno","Las luces de navidad antiguas funcionaban en serie por eso si una fallaba se apagaban todas juntas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["Un circuito en paralelo conecta cada componente directamente a la fuente de alimentación por caminos separados","Cada rama del circuito recibe el mismo voltaje que proporciona la fuente de alimentación principal directamente","Si una bombilla se funde las demás siguen funcionando porque la corriente tiene otros caminos alternativos","La intensidad total es la suma de las intensidades que circulan por cada una de las ramas","Las instalaciones eléctricas de las casas usan circuitos en paralelo para que cada aparato funcione independientemente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["La palanca es una máquina simple que multiplica la fuerza que aplicamos para mover una carga","Está formada por una barra rígida que gira alrededor de un punto fijo llamado punto de apoyo","La fuerza que aplicamos se llama potencia y la fuerza que queremos vencer se llama resistencia","Si el brazo de potencia es más largo que el de resistencia multiplicamos la fuerza aplicada","Las tijeras el cascanueces y la carretilla son ejemplos de palancas que usamos a diario constantemente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["La biela-manivela es un mecanismo que transforma el movimiento circular en movimiento lineal alternativo continuamente","La manivela gira describiendo un movimiento circular completo alrededor de su eje central fijo de rotación","La biela conecta la manivela con un émbolo o pistón que se mueve en línea recta","Cuando la manivela gira el émbolo sube y baja dentro de un cilindro de forma alternativa","Este mecanismo es el principio de funcionamiento de los motores de combustión interna de los coches"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["El motor eléctrico transforma la energía eléctrica en energía mecánica de rotación para mover máquinas","Dentro del motor hay un imán fijo y una bobina de cobre que puede girar libremente","Cuando la corriente eléctrica pasa por la bobina se genera un campo magnético a su alrededor","La interacción entre el campo de la bobina y el del imán produce una fuerza de giro","Invirtiendo la corriente periódicamente el motor mantiene un giro continuo que puede mover cualquier mecanismo conectado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["El tornillo y la tuerca forman una unión desmontable que permite fijar piezas de forma segura","El tornillo tiene un vástago con una rosca helicoidal que encaja en la rosca interna de la tuerca","Al girar el tornillo avanza dentro de la tuerca apretando las piezas que están entre ambos","La llave inglesa o la llave fija se usan para apretar o aflojar la tuerca con facilidad","Para evitar que se afloje con las vibraciones se puede añadir una arandela de seguridad intermedia"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["La energía eléctrica se mide en kilovatios hora que indican la potencia consumida durante un tiempo","La potencia de un aparato en vatios indica cuánta energía consume por cada segundo de funcionamiento","Para calcular el consumo multiplico la potencia del aparato por las horas que está encendido funcionando","Una bombilla de sesenta vatios encendida diez horas consume seiscientos vatios hora o cero coma seis kilovatios hora","La factura eléctrica cobra por cada kilovatio hora consumido más impuestos y costes fijos del suministro"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{2}', '["El sistema de engranajes de una bicicleta permite adaptar la fuerza del pedaleo al terreno actual","El plato delantero grande combinado con el piñón trasero pequeño produce una marcha larga rápida dura","El plato pequeño combinado con el piñón grande produce una marcha corta lenta pero fácil de pedalear","Para subir cuestas usamos marchas cortas que multiplican nuestra fuerza aunque la velocidad sea menor","Para ir rápido en llano usamos marchas largas que multiplican la velocidad aprovechando nuestra potencia muscular"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["Los semiconductores son materiales que conducen la electricidad en ciertas condiciones pero no en otras siempre","El silicio es el semiconductor más utilizado y se obtiene de la arena de cuarzo purificada","Al añadir impurezas al silicio mediante un proceso llamado dopaje se modifica su conductividad eléctrica controladamente","Los semiconductores tipo N tienen exceso de electrones y los tipo P tienen déficit de electrones libres","La unión de un semiconductor P con un N crea un diodo que solo deja pasar corriente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["Una central termoeléctrica genera electricidad quemando combustibles fósiles como carbón gas natural o petróleo refinado","El combustible se quema en una caldera para calentar agua y producir vapor a alta presión","El vapor a presión hace girar las aspas de una turbina que está conectada a un generador","El generador convierte la energía mecánica del giro en energía eléctrica por inducción electromagnética directa","Un transformador eleva el voltaje para transportar la electricidad por las líneas de alta tensión eficientemente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["La energía solar fotovoltaica convierte la luz del sol directamente en electricidad usando paneles solares especiales","Cada panel está formado por muchas células fotovoltaicas de silicio que absorben los fotones solares incidentes","Los fotones liberan electrones en el silicio generando una corriente eléctrica continua dentro de la célula","Un inversor convierte la corriente continua generada en corriente alterna que usamos en nuestros hogares habitualmente","La energía sobrante puede almacenarse en baterías o inyectarse a la red eléctrica general para otros usuarios"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["El transistor es un componente electrónico fundamental que puede amplificar señales o actuar como interruptor automático","Tiene tres terminales llamados base colector y emisor que controlan el flujo de corriente eléctrica interna","Una pequeña corriente aplicada a la base permite controlar una corriente mucho mayor entre colector y emisor","Cuando la base recibe señal el transistor conduce y cuando no la recibe se bloquea completamente","Los microprocesadores modernos contienen miles de millones de transistores miniaturizados en un chip de silicio diminuto"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["La energía eólica aprovecha la fuerza del viento para generar electricidad limpia y renovable continuamente","El viento hace girar las palas del aerogenerador que están conectadas a un eje de rotación","El eje transmite el movimiento a un multiplicador que aumenta la velocidad de giro considerablemente mucho","El generador eléctrico convierte la energía mecánica del giro en electricidad de corriente alterna útil","Un parque eólico agrupa muchos aerogeneradores y puede suministrar electricidad a miles de hogares cercanos simultáneamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["Las comunicaciones inalámbricas transmiten información sin cables usando ondas electromagnéticas que viajan por el aire","El emisor convierte la información en una señal eléctrica que modula una onda portadora de radio","La antena emisora irradia la onda electromagnética modulada que se propaga por el espacio a la velocidad de luz","La antena receptora capta la onda y la convierte de nuevo en una señal eléctrica procesable","El receptor demodula la señal extrayendo la información original que puede ser voz datos o vídeo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["La fibra óptica transmite datos usando pulsos de luz que viajan por hilos de vidrio muy finos","La fuente de luz un láser o LED genera pulsos luminosos que representan los datos binarios","Los pulsos de luz entran en la fibra y viajan por su interior rebotando en las paredes","Al ser luz no sufre interferencias electromagnéticas y puede transmitir datos a velocidades enormes gigantescas","Un solo cable de fibra óptica puede transportar millones de llamadas telefónicas simultáneas a miles de kilómetros"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["Una central nuclear genera electricidad mediante la fisión de átomos de uranio en el reactor atómico","El uranio enriquecido se coloca en barras dentro del reactor donde los neutrones provocan la fisión","La fisión libera una enorme cantidad de calor que calienta agua y produce vapor a alta presión","El vapor mueve una turbina conectada a un generador que produce electricidad de gran potencia eléctrica","Los residuos radiactivos son muy peligrosos y deben almacenarse de forma segura durante miles de años"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["El condensador es un componente electrónico que almacena energía eléctrica en un campo eléctrico interno temporal","Está formado por dos placas conductoras separadas por un material aislante llamado dieléctrico no conductor","Cuando se conecta a una fuente de voltaje las placas se cargan almacenando energía entre ellas","Al desconectar la fuente el condensador mantiene la carga y puede liberarla cuando se necesite rápidamente","Se usa en filtros temporizadores flashes de cámara y para estabilizar la tensión en circuitos electrónicos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{3}', '["La domótica automatiza las funciones de una vivienda para mejorar el confort la seguridad y el ahorro","Sensores de temperatura luz y presencia recogen información del entorno de la casa constantemente sin parar","Un controlador central procesa los datos de los sensores y toma decisiones según la programación establecida","Los actuadores ejecutan las órdenes como encender luces bajar persianas o activar la calefacción automáticamente","El usuario puede controlar y supervisar todo desde una aplicación móvil estando fuera de casa lejos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["La electrónica digital trabaja con señales que solo tienen dos estados posibles representados como cero y uno","El cero representa ausencia de señal o nivel bajo de voltaje en el circuito digital electrónico","El uno representa presencia de señal o nivel alto de voltaje en el circuito lógico interno","Las puertas lógicas son circuitos básicos que realizan operaciones con estos valores binarios de entrada","Combinando miles de puertas lógicas se construyen procesadores capaces de ejecutar millones de operaciones por segundo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["Un sistema de control automático mantiene una variable en un valor deseado sin intervención humana constante","El sensor mide la variable del sistema como la temperatura actual de una habitación climatizada siempre","El controlador compara el valor medido con el valor deseado y calcula la diferencia o error existente","Si hay error el controlador envía una orden al actuador para corregir la desviación detectada rápidamente","El actuador ejecuta la acción correctora como encender el calentador hasta que la temperatura alcance el objetivo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["La puerta lógica AND produce una salida uno solo cuando todas sus entradas están en uno","Si la entrada A es uno y la entrada B es uno la salida será uno activa","Si cualquiera de las entradas es cero la salida será cero inactiva siempre sin excepción","Es como dos interruptores en serie ambos deben estar cerrados para que la bombilla se encienda","Se representa con el símbolo de un semicírculo con punta y su tabla de verdad tiene cuatro filas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["Las energías renovables son inagotables y no producen gases de efecto invernadero durante su funcionamiento normal","La energía solar aprovecha la radiación del sol mediante paneles fotovoltaicos o colectores térmicos de agua","La energía eólica usa la fuerza del viento para mover aerogeneradores que producen electricidad limpia renovable","La energía hidroeléctrica aprovecha la caída del agua desde una presa para mover turbinas generadoras potentes","La energía geotérmica utiliza el calor interno de la Tierra para generar electricidad o calentar edificios"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["Un robot industrial está formado por una estructura mecánica sensores actuadores y un sistema de control","La estructura mecánica incluye brazos articulaciones y una base que le dan movilidad y alcance necesarios","Los sensores proporcionan información del entorno como la posición de objetos la fuerza y la distancia","Los actuadores son motores que mueven las articulaciones del robot siguiendo las órdenes del controlador programado","El programa de control coordina todos los movimientos del robot para que ejecute su tarea con precisión"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["El microcontrolador Arduino permite crear proyectos electrónicos programables de forma sencilla y económica para estudiantes","Conectamos sensores a los pines de entrada para que Arduino lea datos del entorno real exterior","Escribimos un programa en el IDE de Arduino usando un lenguaje basado en C simplificado fácil","El programa lee los sensores procesa la información y envía órdenes a los actuadores de salida","Cargamos el programa en la placa Arduino mediante cable USB y el proyecto empieza a funcionar"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["La huella de carbono mide la cantidad total de gases de efecto invernadero que generamos individualmente","Incluye las emisiones de transporte alimentación consumo energético del hogar y compra de productos manufacturados diversos","Calcularla nos ayuda a identificar qué actividades cotidianas generan más emisiones contaminantes para el medio ambiente","Reducir la huella de carbono implica usar transporte público consumir productos locales y ahorrar energía en casa","Las empresas también calculan su huella de carbono y buscan reducirla como parte de su responsabilidad ambiental"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["Las redes de comunicación se clasifican según su alcance geográfico en LAN MAN y WAN distintas","Una red LAN conecta dispositivos en un área pequeña como una casa una oficina o un aula","Una red MAN cubre una ciudad conectando varias redes LAN entre edificios y zonas urbanas distantes","Una red WAN conecta redes de diferentes ciudades o países como la propia red de Internet global","Todas las redes usan protocolos como TCP e IP que establecen las reglas de comunicación entre dispositivos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["La impresión tridimensional construye objetos físicos capa por capa a partir de un modelo digital diseñado","Primero se diseña el objeto en un programa de modelado tridimensional como TinkerCAD o Fusion completo","El software de laminado divide el modelo en cientos de capas horizontales finas y genera las instrucciones","La impresora calienta el filamento de plástico hasta fundirlo y lo deposita siguiendo las instrucciones recibidas","Capa tras capa el objeto va tomando forma hasta completar la pieza tridimensional sólida final deseada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tecnologia', 'eso', '{4}', '["La economía circular propone un modelo productivo donde los residuos se convierten en recursos nuevos reutilizables","En el modelo lineal tradicional se extrae se fabrica se usa y se desecha generando enormes residuos","La economía circular diseña productos para que al final de su vida útil se puedan reciclar totalmente","Los materiales recuperados se reintroducen en el proceso productivo reduciendo la necesidad de extraer materias primas nuevas","Este modelo reduce la contaminación ahorra recursos naturales y crea nuevas oportunidades de negocio sostenibles e innovadoras"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Noto que estoy muy enfadado porque un compañero ha cogido mi material sin pedirme permiso primero","Respiro profundamente tres veces para calmarme antes de reaccionar de forma impulsiva y descontrolada agresivamente","Pienso en cómo expresar lo que siento sin gritar ni insultar a mi compañero de clase","Me acerco a mi compañero y le explico con calma que me ha molestado su acción","Mi compañero se disculpa y acordamos que la próxima vez pedirá permiso antes de coger nada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Me doy cuenta de que siempre dejo todo para el último momento y me agobio mucho","Decido crear un horario de estudio semanal donde organizo las tareas por días y asignaturas","Cada tarde reviso qué deberes tengo y los apunto en mi agenda escolar ordenadamente por prioridad","Empiezo por las tareas más difíciles cuando tengo más energía y dejo las fáciles para después","Después de unas semanas siguiendo el horario noto que llego más tranquilo a los exámenes preparados"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Un compañero nuevo llega a clase a mitad de curso y no conoce a nadie todavía","Noto que está solo en el recreo sentado en un banco sin hablar con ningún compañero","Me acerco a saludarle y le pregunto su nombre y de dónde viene con interés sincero","Le presento a mis amigos y le invitamos a jugar con nosotros durante el recreo completo","Poco a poco el compañero nuevo se integra en el grupo y hace amistades con todos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Tenemos que hacer un trabajo en equipo de cuatro personas para la clase de ciencias","Nos reunimos y repartimos las tareas según las habilidades y preferencias de cada miembro del grupo","Establecemos fechas límite para entregar cada parte y un canal de comunicación para coordinarnos bien","Un compañero no cumple con su parte y los demás nos sentimos frustrados y preocupados bastante","Hablamos con él para entender el problema y le ayudamos a completar su tarea a tiempo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Observo que un compañero recibe insultos y burlas de un grupo de alumnos cada día constantemente","Me doy cuenta de que eso es acoso escolar y que la víctima lo está pasando muy mal","Hablo con un profesor de confianza y le cuento la situación que estoy observando sin exagerar","El profesor habla con los acosadores y con la víctima para resolver la situación de forma adecuada","Se establece un plan de convivencia y el acoso se detiene gracias a la intervención temprana realizada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Suspendo un examen de matemáticas y me siento muy triste y frustrado con el resultado obtenido","Pienso que soy tonto y que nunca voy a aprobar esa asignatura tan difícil para mí","Mi tutor me explica que un suspenso no define mi inteligencia sino que indica áreas de mejora","Analizamos juntos los errores del examen y descubrimos que necesito practicar más los ejercicios de fracciones","Refuerzo esa parte con ejercicios extra y en el siguiente examen apruebo con una nota mucho mejor"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Quiero aprender a escuchar mejor a mis amigos cuando me cuentan sus problemas personales importantes","Practico la escucha activa mirando a los ojos y asintiendo mientras la otra persona habla conmigo","Evito interrumpir aunque tenga ganas de dar mi opinión antes de que termine de explicarse completamente","Cuando termina de hablar resumo lo que me ha dicho para comprobar que lo he entendido bien","Mi amigo se siente comprendido y valorado porque nota que realmente he prestado atención a sus palabras"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Empiezo el instituto y me siento nervioso porque todo es nuevo y no conozco a muchos","El primer día observo las instalaciones las aulas y los horarios intentando orientarme por el centro educativo","Poco a poco conozco a mis compañeros de clase y descubro que varios comparten mis mismos intereses","Los profesores nos explican las normas del centro y lo que esperan de nosotros como alumnos nuevos","Después de unas semanas ya me siento cómodo y el instituto me parece un lugar agradable"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Una amiga me cuenta un secreto personal y me pide que no se lo cuente a nadie","Al día siguiente otros compañeros me preguntan sobre el tema y me presionan para que hable","Recuerdo la confianza que mi amiga depositó en mí y decido guardar su secreto firmemente","Les digo a los compañeros que no sé nada y cambio de tema de conversación con naturalidad","Mi amiga se entera de que mantuve su secreto y nuestra amistad se fortalece por la confianza"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Noto que paso demasiadas horas al día mirando el móvil y las redes sociales sin control","Me comparo constantemente con las vidas perfectas que otros muestran en Instagram y me siento mal","Decido limitar el tiempo de pantalla a una hora diaria y desactivar las notificaciones innecesarias molestas","Empiezo a dedicar el tiempo libre a actividades que me gustan como leer dibujar o hacer deporte","Después de unas semanas me siento más tranquilo y mi autoestima mejora al dejar de compararme"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Tengo un conflicto con un amigo porque ambos queremos ser el capitán del equipo de fútbol","Nos enfadamos y dejamos de hablarnos durante varios días sintiéndonos molestos el uno con el otro","El tutor nos propone usar la mediación para resolver el conflicto de forma pacífica y dialogada","Cada uno expresa cómo se siente y escucha al otro sin interrumpir respetando el turno acordado","Llegamos a un acuerdo justo de turnarnos como capitán y nuestra amistad se recupera completamente reforzada"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Aprendo que la asertividad es expresar mis opiniones y sentimientos respetando siempre los derechos de otros","Una persona pasiva no dice lo que piensa y deja que los demás decidan siempre por ella","Una persona agresiva impone sus ideas gritando o amenazando sin respetar los sentimientos de los demás","Una persona asertiva dice lo que piensa de forma clara tranquila y respetuosa con todos siempre","Practico la asertividad diciendo no cuando algo no me parece bien explicando mis razones con calma"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["El profesor nos pide que identifiquemos nuestras emociones básicas como alegría tristeza enfado y miedo","Aprendo que todas las emociones son normales y válidas incluidas las que nos hacen sentir incómodos","Lo importante no es dejar de sentir sino aprender a gestionar las emociones de forma saludable","Escribo en un diario emocional qué siento cada día y qué situaciones provocan esas emociones intensas","Con el tiempo reconozco mejor mis emociones y puedo expresarlas de forma más adecuada ante los demás"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Descubro que tengo miedo a hablar en público porque me pongo muy nervioso delante de todos","El tutor nos explica técnicas para superar el miedo escénico y ganar confianza al comunicar ideas","Practico primero hablando ante un grupo pequeño de tres compañeros que me apoyan y me animan","Cada vez hago presentaciones ante grupos más grandes y noto que los nervios van disminuyendo progresivamente","Al final del curso consigo hacer una exposición ante toda la clase sintiéndome seguro y tranquilo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Un compañero hace un comentario ofensivo sobre la ropa que llevo puesta y me siento humillado","Algunos se ríen y eso me hace sentir peor porque siento que todos se burlan de mí","Respiro hondo y en vez de devolver el insulto le digo que ese comentario me ha dolido","El compañero se da cuenta de que ha sido cruel y se disculpa sinceramente ante todos nosotros","Aprendemos que las palabras pueden hacer mucho daño y que debemos pensar antes de hablar siempre"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["El tutor nos propone crear unas normas de convivencia para nuestra clase de forma democrática participativa","Cada alumno propone una norma que considere importante para que todos estemos cómodos y seguros aquí","Votamos las normas más importantes y seleccionamos las diez que nos parecen más necesarias fundamentales","Las escribimos en un mural grande que colgamos en la pared para que todos las recordemos siempre","Nos comprometemos a cumplirlas y a respetar las consecuencias si alguno no las cumple voluntariamente después"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Aprendo que la empatía es ponerme en el lugar de otra persona para entender sus sentimientos","Mi compañera está triste porque sus padres se están separando y necesita apoyo emocional de alguien","No le digo que no llore ni que no pasa nada porque eso invalida sus emociones reales","Le digo que entiendo que esté triste y que puede contar conmigo para lo que necesite","Mi compañera se siente acompañada y agradece que alguien la escuche sin juzgarla ni darle consejos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Quiero mejorar mis técnicas de estudio porque siento que estudio mucho pero no aprendo bien","El tutor nos enseña la técnica del subrayado activo donde marco solo las ideas más importantes","También aprendo a hacer resúmenes con mis propias palabras y esquemas que organizan la información clave","Practico la técnica de repasar lo estudiado al día siguiente y una semana después para recordar","Con estas técnicas consigo mejores resultados estudiando menos horas pero de forma mucho más eficiente y productiva"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Un amigo me presiona para que copie en un examen diciéndome que todo el mundo lo hace","Me siento incómodo porque sé que copiar está mal pero no quiero que piense que soy raro","Decido ser honesto y le digo que prefiero sacar la nota que me corresponde por mi esfuerzo","Le explico que copiar no me ayuda a aprender y que si nos pillan las consecuencias son graves","Mi amigo lo entiende y al final también decide estudiar por su cuenta para el próximo examen"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Recibimos una charla sobre los peligros de internet y las redes sociales en la hora de tutoría","Nos explican que no debemos compartir información personal como dirección teléfono o ubicación con desconocidos online","Aprendemos que no todo lo que se publica en internet es verdadero y hay mucha desinformación circulando","Nos enseñan a configurar la privacidad de nuestras cuentas para que solo vean nuestro contenido personas conocidas","Después de la charla reviso mis redes sociales y ajusto la privacidad para sentirme más seguro protegido"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Aprendo que el respeto a la diversidad significa valorar las diferencias entre las personas como algo positivo","En nuestra clase hay compañeros de diferentes países culturas religiones y capacidades que nos enriquecen mutuamente","Descubrimos que cada persona tiene algo valioso que aportar independientemente de su origen o apariencia exterior","Los estereotipos y prejuicios nos impiden conocer realmente a las personas y generan discriminación e injusticia","Comprometerse con la diversidad significa tratar a todos con igualdad respeto y dignidad sin hacer excepciones nunca"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["El tutor nos propone reflexionar sobre qué queremos ser de mayores y qué nos gusta estudiar","Hago una lista de mis aficiones y las asignaturas que más me gustan y mejor se me dan","Investigo qué profesiones se relacionan con mis intereses y qué estudios necesitaría para acceder a ellas","Hablo con mis padres y mi tutor sobre mis ideas para conocer su opinión y sus consejos","Entiendo que todavía tengo tiempo para decidir pero que es bueno empezar a pensar en mi futuro"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Un compañero se burla de otro porque lleva gafas y le pone un mote despectivo cruel humillante","El compañero con gafas se siente muy mal y empieza a no querer venir a clase algunos días","Varios de nosotros decidimos hablar con el que pone motes y explicarle que está haciendo daño real","Le decimos que los motes despectivos son una forma de acoso y que debe parar inmediatamente ahora","El compañero reflexiona se disculpa sinceramente y todos aprendemos que debemos cuidar cómo tratamos a los demás"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Tengo un examen importante mañana y siento mucha ansiedad que me impide concentrarme en estudiar bien","Mi cuerpo reacciona con taquicardia sudoración y un nudo en el estómago que me hace sentir fatal","El tutor nos enseña una técnica de relajación basada en respirar lentamente contando hasta cinco inspirando","Practico la respiración profunda durante cinco minutos y noto cómo la ansiedad disminuye progresivamente poco a poco","Consigo calmarme lo suficiente para estudiar con concentración y al día siguiente hago el examen bien"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Nos organizamos para celebrar el día de la paz en el instituto con actividades especiales variadas","Cada clase prepara una actividad diferente como murales canciones poemas o representaciones teatrales sobre la paz","Decoramos los pasillos con mensajes positivos sobre la convivencia el respeto y la resolución pacífica de conflictos","El día de la celebración compartimos las actividades con todo el instituto en el salón de actos","Reflexionamos sobre la importancia de construir la paz cada día en nuestra vida cotidiana y escolar"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Aprendo a reconocer la diferencia entre un amigo de verdad y alguien que me influye negativamente","Un buen amigo te apoya te respeta y te acepta tal como eres sin intentar cambiarte nunca","Una influencia negativa te presiona para hacer cosas que no quieres o que sabes que están mal","Si alguien te ridiculiza te amenaza o te obliga a algo no es un verdadero amigo tuyo","Elijo rodearme de personas que me hacen sentir bien y me ayudan a ser mejor persona"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Hacemos una dinámica de grupo donde cada compañero escribe algo positivo de los demás en tarjetas","Cada alumno recibe un sobre con las tarjetas que los compañeros han escrito sobre sus cualidades","Al leer los mensajes muchos se sorprenden porque descubren virtudes que no sabían que los demás veían","La actividad genera un ambiente de aprecio mutuo y mejora las relaciones entre todos los compañeros presentes","Aprendemos que decir cosas bonitas a los demás cuesta poco y puede alegrar mucho su día entero"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Detecto que un compañero no come durante el recreo y parece estar muy preocupado por su peso","Me acerco a hablar con él y me cuenta que quiere adelgazar aunque ya está en su peso","Le digo que me preocupa su salud y que hay formas saludables de cuidarse sin dejar de comer","Hablamos con el tutor para que pueda orientarle y derivarle a un profesional si es necesario ahora","Aprendemos que la imagen corporal puede distorsionarse y que pedir ayuda profesional es un acto de valentía"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["El tutor nos propone reflexionar sobre la igualdad de género en nuestra vida cotidiana diaria","Analizamos estereotipos de género como que los chicos no lloran o las chicas no juegan a fútbol","Debatimos por qué esos estereotipos limitan a las personas y les impiden ser quienes realmente quieren ser","Buscamos ejemplos de mujeres y hombres que rompieron estereotipos en la ciencia el deporte o el arte","Nos comprometemos a tratar a todos por igual sin limitar a nadie por su género o apariencia"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{1}', '["Quiero mejorar mi concentración en clase porque a veces me distraigo con facilidad y pierdo información importante","Identifico los principales elementos que me distraen como el móvil el ruido o los pensamientos que divagan mucho","Aplico estrategias como apagar el móvil sentarme cerca del profesor y tomar notas activas durante la explicación","Practico técnicas de atención plena respirando conscientemente cuando noto que mi mente empieza a dispersarse demasiado","Poco a poco noto que mi concentración mejora y aprovecho mucho mejor el tiempo en clase"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["Aprendemos la técnica del mensaje yo para expresar sentimientos sin culpar ni atacar a otra persona","En lugar de decir tú siempre llegas tarde digo yo me siento ignorado cuando llegas tarde","El mensaje yo describe la situación expresa cómo me siento y pide un cambio concreto posible","Esta técnica reduce la defensividad de la otra persona y facilita el diálogo constructivo entre ambos","Practicamos la técnica con situaciones reales de clase y notamos que las discusiones se resuelven mejor así"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["El tutor nos explica las diferentes inteligencias múltiples que cada persona puede tener más desarrolladas","La inteligencia lingüística se relaciona con la facilidad para las palabras la lectura y la escritura","La inteligencia lógico-matemática destaca en el razonamiento numérico los problemas lógicos y el pensamiento analítico abstracto","La inteligencia musical se manifiesta en la capacidad para reconocer ritmos melodías y crear composiciones sonoras","Descubrimos que todos somos inteligentes de formas diferentes y que cada inteligencia es valiosa e importante"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["Dos compañeras de clase tienen un conflicto porque una ha difundido un rumor falso sobre la otra","La afectada se siente traicionada y enfadada y ha dejado de hablar con su compañera completamente","El tutor propone una mediación donde ambas partes puedan expresarse y ser escuchadas en un espacio seguro","La mediadora ayuda a cada una a expresar sus sentimientos y a entender la perspectiva de la otra","Llegan a un acuerdo donde la que difundió el rumor se disculpa públicamente y se compromete a no repetirlo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["Reflexionamos sobre el consumo responsable y cómo nuestras decisiones de compra afectan al planeta entero","Analizamos la publicidad y cómo nos manipula para hacernos desear cosas que realmente no necesitamos comprar","Aprendemos a distinguir entre necesidades reales y deseos creados por la presión social y el marketing","El tutor nos propone un reto de una semana sin comprar nada innecesario para reflexionar juntos","Al final del reto compartimos nuestras experiencias y descubrimos que podemos ser más felices con menos cosas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["Hacemos una actividad sobre comunicación no verbal para entender que el cuerpo también transmite mensajes claros","Los gestos la postura el contacto visual y el tono de voz comunican tanto como las palabras","Un compañero dice estoy bien pero con los brazos cruzados y sin mirar a los ojos","Detectamos que su lenguaje corporal contradice sus palabras y probablemente no se encuentra realmente bien hoy","Aprendemos que para comunicarnos mejor debemos prestar atención tanto a lo que se dice como al cómo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["El tutor nos habla sobre la importancia de tener una autoestima sana basada en el autoconocimiento","Hacemos un ejercicio donde escribimos cinco cualidades positivas nuestras y cinco aspectos que queremos mejorar personalmente","Compartimos nuestras listas con un compañero de confianza que puede añadir cualidades que nosotros no vemos","Descubrimos que a menudo somos más duros con nosotros mismos de lo que los demás perciben","Aprendemos que la autoestima se construye reconociendo nuestros logros aceptando nuestros errores y siendo compasivos con nosotros"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["Recibimos una charla sobre el ciberacoso y cómo actuar si somos víctimas o testigos de ello","El ciberacoso incluye insultos amenazas difusión de fotos privadas y exclusión deliberada en grupos de mensajería","Nos enseñan a guardar las pruebas del acoso como capturas de pantalla antes de bloquear al acosador","Debemos contárselo a un adulto de confianza como padres tutores o al coordinador de convivencia del centro","La persona que acosa en internet puede enfrentarse a consecuencias legales graves además de las disciplinarias escolares"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["Hacemos un debate en clase sobre si los deberes son necesarios o si deberían eliminarse completamente","Dividimos la clase en dos grupos uno a favor de los deberes y otro en contra argumentando","El grupo a favor argumenta que los deberes refuerzan lo aprendido y crean hábitos de estudio responsables","El grupo en contra argumenta que restan tiempo libre y pueden causar estrés y desmotivación excesiva","Al final aprendemos que lo importante es debatir con respeto escuchar al otro y argumentar con datos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["Reflexionamos sobre la gestión del tiempo libre y la importancia del ocio saludable para nuestro bienestar","El tiempo libre no es solo descansar sino también una oportunidad para crecer aprender y disfrutar activamente","Hacemos una lista de actividades de ocio saludable como deportes lectura música voluntariado y tiempo con amigos","Comparamos el tiempo que dedicamos a pantallas con el que dedicamos a actividades activas y presenciales sociales","Nos proponemos equilibrar mejor nuestro tiempo libre incluyendo actividades que nos hagan sentir realizados y contentos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{2}', '["El tutor nos enseña la técnica del semáforo para gestionar emociones intensas en momentos de conflicto","La luz roja significa parar reconocer que estoy sintiendo una emoción muy intensa y necesito calmarme primero","La luz amarilla significa pensar analizar qué ha pasado y qué opciones tengo para responder adecuadamente","La luz verde significa actuar elegir la mejor opción y ponerla en práctica de forma calmada responsable","Practicamos la técnica con casos reales y descubrimos que unos segundos de pausa evitan muchos problemas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["Empiezo a pensar en qué itinerario académico elegir para cuarto de ESO el próximo curso","El tutor nos explica las diferentes opciones de asignaturas optativas y sus implicaciones para el futuro","Investigo qué estudios de bachillerato o formación profesional me interesan más según mis gustos y capacidades","Hablo con mi familia y con el orientador del centro para recibir información y consejo personalizado","Tomo una decisión informada eligiendo las asignaturas que mejor se ajustan a mis intereses vocacionales actuales"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["Participamos en un proyecto de aprendizaje servicio donde ayudamos a personas mayores con las tecnologías digitales","Visitamos un centro de día y conocemos a los usuarios que quieren aprender a usar el móvil","Les enseñamos a hacer videollamadas enviar mensajes de texto y usar aplicaciones básicas de forma paciente","Descubrimos que las personas mayores tienen mucha sabiduría y experiencia que compartir con nosotros también generosamente","La experiencia nos enseña el valor de la solidaridad intergeneracional y la satisfacción de ayudar a otros"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["Analizamos en tutoría cómo la presión de grupo puede llevarnos a tomar decisiones arriesgadas peligrosas","El tutor nos presenta casos reales donde adolescentes hicieron cosas peligrosas por la presión de sus amigos","Reflexionamos sobre por qué es tan difícil decir que no cuando todo el grupo quiere hacer algo","Practicamos respuestas asertivas para resistir la presión como decir no me apetece sin sentir vergüenza alguna","Aprendemos que un amigo de verdad respeta tu decisión y no te obliga a hacer nada arriesgado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["El tutor nos propone un ejercicio de resolución de problemas usando el método de los seis pasos","Primero identificamos el problema concreto describiéndolo de forma clara y objetiva sin emociones ni juicios","Después generamos todas las soluciones posibles mediante una lluvia de ideas sin juzgar ninguna propuesta inicialmente","Evaluamos cada solución analizando sus ventajas e inconvenientes y las consecuencias de cada una por separado","Elegimos la mejor solución la ponemos en práctica y después evaluamos si ha funcionado bien o no"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["Debatimos sobre los derechos humanos y su importancia fundamental para la convivencia pacífica en sociedad","La Declaración Universal de los Derechos Humanos fue aprobada en mil novecientos cuarenta y ocho por la ONU","Establece que todos los seres humanos nacen libres e iguales en dignidad y derechos fundamentales inalienables","Sin embargo muchos derechos como la educación la libertad y la igualdad no se respetan en muchos países","Cada ciudadano tiene la responsabilidad de conocer defender y promover los derechos humanos en su entorno cercano"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["Hacemos un taller sobre educación financiera básica para aprender a gestionar nuestro dinero de forma responsable","Aprendemos la diferencia entre ingresos y gastos y la importancia de no gastar más de lo ingresado","El tutor nos enseña a crear un presupuesto mensual sencillo donde planificamos en qué gastar nuestro dinero","Practicamos distinguiendo entre gastos necesarios como material escolar y gastos opcionales como videojuegos o ropa de marca","Entendemos que ahorrar una parte de nuestros ingresos nos permite afrontar imprevistos y alcanzar metas futuras deseadas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["Reflexionamos sobre el uso ético de las redes sociales y nuestra responsabilidad como ciudadanos digitales activos","Analizamos casos de personas que sufrieron consecuencias graves por publicar contenido inapropiado en sus perfiles públicos","Debatimos sobre la diferencia entre libertad de expresión y discurso de odio que daña a otros usuarios","Establecemos un código de conducta digital para nuestra clase que incluye respeto veracidad y privacidad online","Nos comprometemos a pensar antes de publicar y a denunciar contenidos que promuevan el odio o la violencia"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["El orientador del centro nos presenta las diferentes familias profesionales y las opciones de formación profesional","Descubrimos que la formación profesional ofrece titulaciones de grado medio y grado superior en muchos sectores","Investigamos los ciclos formativos que más nos interesan como informática sanidad administración o electricidad industrial","Algunos alumnos visitan centros de formación profesional para conocer de primera mano las instalaciones y profesores","Entendemos que la FP es una opción tan válida como el bachillerato y ofrece alta empleabilidad laboral"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["Hacemos un taller de primeros auxilios donde aprendemos a actuar ante emergencias básicas cotidianas frecuentes","Nos enseñan el protocolo PAS que significa proteger avisar y socorrer en el orden correcto siempre","Practicamos la posición lateral de seguridad para colocar a una persona inconsciente que respira con normalidad","Aprendemos a realizar la maniobra de Heimlich para actuar ante un atragantamiento grave en alguien cercano","Al final del taller nos sentimos más preparados y seguros para reaccionar ante situaciones de emergencia real"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{3}', '["Reflexionamos sobre la importancia de la motivación intrínseca frente a la motivación extrínseca en el estudio","La motivación extrínseca viene de fuera como las notas los premios o el miedo al castigo recibido","La motivación intrínseca nace del interés personal la curiosidad y la satisfacción de aprender cosas nuevas","Cuando estudia por motivación intrínseca el alumno disfruta más retiene mejor la información y se esfuerza más","El tutor nos ayuda a encontrar aspectos interesantes en cada asignatura para despertar nuestra curiosidad natural propia"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["Llega el momento de decidir si quiero hacer bachillerato formación profesional o incorporarme al mercado laboral","El orientador me ayuda a analizar mis intereses aptitudes valores y rendimiento académico de forma objetiva","Investigo las salidas profesionales de cada opción comparando las ventajas y requisitos de acceso de cada una","Hablo con personas que estudian o trabajan en los campos que me interesan para conocer su experiencia","Tomo una decisión reflexionada sabiendo que puedo reconducir mi camino si en el futuro cambio de opinión"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["Participamos en un proyecto sobre los Objetivos de Desarrollo Sostenible de la ONU y su importancia global","Investigamos los diecisiete objetivos como fin de la pobreza educación de calidad y acción por el clima","Cada grupo elige un objetivo y analiza qué se está haciendo en España para cumplirlo antes de 2030","Proponemos acciones concretas que podemos realizar desde nuestro centro educativo para contribuir a esos objetivos globales","Presentamos nuestras propuestas al equipo directivo y algunas se incorporan al plan de convivencia del centro"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["Reflexionamos sobre la importancia de desarrollar un pensamiento crítico ante la información que recibimos constantemente","Analizamos noticias reales y noticias falsas intentando identificar las características que las diferencian entre sí claramente","Aprendemos a verificar las fuentes contrastar la información y buscar la intención detrás de cada mensaje publicado","Descubrimos que los algoritmos de las redes sociales nos muestran contenido que refuerza nuestras creencias previas","Nos comprometemos a cuestionar la información verificar antes de compartir y buscar fuentes diversas y fiables"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["El tutor nos propone elaborar un proyecto de vida personal que nos ayude a definir nuestras metas","Reflexionamos sobre quiénes somos qué nos importa y qué tipo de persona queremos llegar a ser","Definimos metas a corto plazo para este curso a medio plazo para los próximos tres años","Identificamos los obstáculos que podrían dificultar nuestras metas y planificamos estrategias para superarlos con determinación","Escribimos nuestro proyecto de vida sabiendo que es un documento vivo que iremos actualizando con el tiempo"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["Hacemos un taller sobre relaciones afectivas saludables y cómo identificar señales de relaciones tóxicas dañinas","Analizamos las características de una relación sana como respeto confianza comunicación libertad individual y apoyo mutuo","Identificamos señales de alerta como los celos excesivos el control del móvil y el aislamiento social","Debatimos sobre el consentimiento y la importancia de respetar los límites que cada persona establece libremente","Aprendemos que nadie tiene derecho a controlar manipular o agredir a su pareja bajo ninguna circunstancia jamás"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["Organizamos un simulacro de entrevista de trabajo para practicar las habilidades necesarias en el mundo laboral","Preparamos nuestro primer currículum vitae incluyendo formación habilidades idiomas y experiencias relevantes que tengamos hasta ahora","Investigamos la empresa ficticia y preparamos respuestas a las preguntas más frecuentes de las entrevistas laborales","Un profesional externo hace de entrevistador y nos evalúa dándonos consejos para mejorar nuestra presentación personal","Aprendemos la importancia de la puntualidad la imagen personal la comunicación clara y la actitud positiva profesional"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["Debatimos sobre la ética en las nuevas tecnologías y los dilemas morales que plantean a la sociedad","Analizamos el caso de la privacidad de datos y cómo las grandes empresas tecnológicas recopilan información","Reflexionamos sobre la inteligencia artificial y si las máquinas deberían tomar decisiones que afectan a personas","Discutimos sobre la brecha digital y cómo la falta de acceso a tecnología genera desigualdad entre países","Concluimos que la tecnología es una herramienta y que nosotros como sociedad debemos decidir cómo usarla justamente"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["Hacemos una actividad de autoconocimiento profundo para identificar nuestras fortalezas debilidades oportunidades y amenazas personales","Las fortalezas son nuestras cualidades internas como la creatividad la perseverancia o la capacidad de comunicar bien","Las debilidades son aspectos internos que podemos mejorar como la impaciencia la desorganización o la timidez","Las oportunidades son factores externos favorables como becas programas de intercambio o apoyo familiar incondicional recibido","Las amenazas son factores externos que pueden dificultar nuestras metas como la situación económica o la presión"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["Participamos en un proyecto de voluntariado donde colaboramos con una ONG local que ayuda a familias vulnerables","Antes de empezar recibimos formación sobre las causas de la exclusión social y las formas de ayudar","Durante varias semanas participamos en actividades como reparto de alimentos apoyo escolar y talleres de integración","La experiencia nos hace conscientes de las desigualdades sociales y de nuestra capacidad para contribuir al cambio","Reflexionamos sobre cómo la solidaridad y el compromiso social nos enriquecen como personas y como ciudadanos responsables"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('tutoria', 'eso', '{4}', '["El tutor nos propone reflexionar sobre la resiliencia la capacidad de superar adversidades y salir fortalecido","Analizamos historias de personas que superaron situaciones muy difíciles como enfermedades pérdidas o fracasos graves importantes","Identificamos los factores que les ayudaron como el apoyo social la actitud positiva y la perseverancia constante","Reflexionamos sobre dificultades que nosotros hemos superado y qué aprendimos de esas experiencias difíciles vividas personalmente","Entendemos que los fracasos y las dificultades son parte de la vida y pueden hacernos más fuertes"]');
